import React from 'react';
import { Play } from 'lucide-react';
import { SearchResult } from '../types';
import { getImageUrl } from '../services/api';
import { useNavigate } from 'react-router-dom';

interface SongCardProps {
  item: SearchResult;
  onPlay?: () => void;
  subtitle?: string;
  round?: boolean;
}

export const SongCard: React.FC<SongCardProps> = ({ item, onPlay, subtitle, round = false }) => {
  const navigate = useNavigate();
  const imageUrl = getImageUrl(item.image);

  const handleClick = () => {
    if (item.type === 'album') {
      navigate(`/album/${item.id}`);
    } else if (item.type === 'artist') {
      navigate(`/artist/${item.id}`, { state: { artist: item } });
    } else if (item.type === 'song' && onPlay) {
      onPlay();
    } else if (item.type === 'playlist') {
      navigate(`/playlist/${item.id}`);
    }
  };

  const handlePlayClick = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (onPlay) onPlay();
  };

  let safeSubtitle = subtitle;
  if (!safeSubtitle) {
      if (item.type === 'song') {
          safeSubtitle = item.artists?.primary?.[0]?.name || 'Artist';
      } else if (item.type === 'album') {
          safeSubtitle = `${item.year} • ${item.artists?.primary?.[0]?.name || 'Artist'}`;
      } else if (item.type === 'artist') {
          safeSubtitle = 'Artist';
      } else if (item.type === 'playlist') {
          safeSubtitle = item.subtitle || `By ${'User'}`;
      }
  }

  const displayTitle = item.type === 'playlist' ? item.title : item.name;

  return (
    <div 
      onClick={handleClick}
      className="group relative bg-[#181818] hover:bg-[#282828] p-4 rounded-lg transition-colors duration-300 cursor-pointer w-[160px] md:w-[190px] shrink-0"
    >
      <div className={`relative w-full aspect-square mb-4 shadow-lg ${round ? 'rounded-full' : 'rounded-md'} overflow-hidden`}>
        <img 
          src={imageUrl} 
          alt={displayTitle} 
          className="w-full h-full object-cover"
          loading="lazy"
        />

        {/* Play Button Overlay (Slides Up) */}
        {!round && (
          <div className="absolute bottom-2 right-2 translate-y-4 opacity-0 group-hover:translate-y-0 group-hover:opacity-100 transition-all duration-300 z-20">
             <button 
                onClick={handlePlayClick}
                className="w-12 h-12 bg-[#1DB954] rounded-full flex items-center justify-center shadow-xl hover:scale-105 active:scale-95 transition-transform"
             >
                <Play size={24} fill="black" className="text-black ml-1" />
             </button>
          </div>
        )}
      </div>

      <div className="flex flex-col min-h-[62px]">
        <h3 className="text-white font-bold truncate text-[16px] mb-1 pb-1">
          {displayTitle}
        </h3>
        <p className="text-[#A7A7A7] text-[13px] line-clamp-2 font-medium leading-relaxed">
          {safeSubtitle}
        </p>
      </div>
    </div>
  );
};

import React, { useRef, useEffect, useState } from 'react';
import { Play, Pause, SkipBack, SkipForward, ChevronDown, Repeat, Shuffle, Mic2, ListMusic, Volume2, Maximize2, Heart, Share2 } from 'lucide-react';
import { usePlayerStore } from '../store/playerStore';
import { getImageUrl, getAudioUrl, getOfflineAudioUrl } from '../services/api';
import { AnimatePresence, motion } from 'framer-motion';
import { DownloadQualityModal } from './DownloadQualityModal';
import { Song } from '../types';
import { useNavigate } from 'react-router-dom';

export const Player: React.FC = () => {
  const { 
    currentSong, isPlaying, isBuffering, isFullScreen, setFullScreen, togglePlay, setIsPlaying, 
    setIsBuffering, nextSong, prevSong, likedSongs, toggleLike, isShuffling, 
    streamingQuality, isOfflineMode, downloadedSongIds, volume, setVolume
  } = usePlayerStore();

  const navigate = useNavigate();
  const audioRef = useRef<HTMLAudioElement>(null);
  const [progress, setProgress] = useState(0);
  const [duration, setDuration] = useState(0);
  const [dominantColor, setDominantColor] = useState<string>('#121212');
  const [isDragging, setIsDragging] = useState(false);
  const [downloadSong, setDownloadSong] = useState<Song | null>(null);

  const isLiked = currentSong ? likedSongs.some(s => s.id === currentSong.id) : false;

  // --- AUDIO LOGIC ---
  useEffect(() => {
    if (!currentSong) return;
    const imgUrl = getImageUrl(currentSong.image);
    // Simple color fallback for now
    setDominantColor('#242424'); 
  }, [currentSong?.id]);

  useEffect(() => {
    if (!currentSong || !audioRef.current) return;
    const setAudioSource = async () => {
        let url = '';
        if (isOfflineMode || downloadedSongIds.includes(currentSong.id)) {
            const blobUrl = await getOfflineAudioUrl(currentSong.id);
            if (blobUrl) url = blobUrl;
        }
        if (!url && !isOfflineMode) url = getAudioUrl(currentSong.downloadUrl, streamingQuality);

        if (url && audioRef.current && audioRef.current.src !== url) {
            const wasPlaying = isPlaying;
            audioRef.current.src = url;
            audioRef.current.load();
            if (wasPlaying) audioRef.current.play().catch(() => setIsPlaying(false));
        }
    };
    setAudioSource();
  }, [currentSong?.id, streamingQuality, isOfflineMode]);

  useEffect(() => {
    const audio = audioRef.current;
    if (!audio) return;
    if (isPlaying && audio.paused) audio.play().catch(() => {});
    else if (!isPlaying && !audio.paused) audio.pause();
    audio.volume = volume;
  }, [isPlaying, volume]);

  const handleTimeUpdate = () => {
    if (audioRef.current && !isDragging) {
      setProgress(audioRef.current.currentTime);
      setDuration(audioRef.current.duration || 0);
    }
  };

  const handleSeek = (e: React.ChangeEvent<HTMLInputElement>) => {
    const time = parseFloat(e.target.value);
    setProgress(time);
    if (audioRef.current) audioRef.current.currentTime = time;
  };

  const formatTime = (seconds: number) => {
    if (!seconds || isNaN(seconds)) return "-:--";
    const mins = Math.floor(seconds / 60);
    const secs = Math.floor(seconds % 60);
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  if (!currentSong) return null;

  const imageUrl = getImageUrl(currentSong.image);
  const primaryArtistName = currentSong.artists?.primary?.[0]?.name || "Unknown";

  return (
    <>
        <audio 
            ref={audioRef}
            preload="auto"
            onTimeUpdate={handleTimeUpdate}
            onEnded={nextSong}
            onWaiting={() => setIsBuffering(true)}
            onPlaying={() => setIsBuffering(false)}
            onCanPlay={() => setIsBuffering(false)}
            onPause={() => !isBuffering && setIsPlaying(false)}
            onPlay={() => !isPlaying && setIsPlaying(true)}
        />

        {/* --- DESKTOP FOOTER BAR (Hidden on Mobile) --- */}
        <div className="hidden md:flex fixed bottom-0 left-0 right-0 h-[90px] bg-[#000000] border-t border-[#282828] px-4 items-center justify-between z-[100]">

             {/* Left: Track Info */}
             <div className="flex items-center gap-4 w-[30%] min-w-[180px]">
                 <img src={imageUrl} alt="" className="h-14 w-14 rounded-md object-cover shadow-sm cursor-pointer" onClick={() => setFullScreen(true)}/>
                 <div className="flex flex-col justify-center overflow-hidden">
                     <span className="text-sm font-bold text-white hover:underline cursor-pointer truncate">{currentSong.name}</span>
                     <span className="text-xs text-[#B3B3B3] hover:text-white hover:underline cursor-pointer truncate">{primaryArtistName}</span>
                 </div>
                 <button onClick={() => toggleLike(currentSong)} className={`ml-2 ${isLiked ? 'text-[#1DB954]' : 'text-[#B3B3B3] hover:text-white'}`}>
                     <Heart size={16} fill={isLiked ? "currentColor" : "none"} />
                 </button>
             </div>

             {/* Center: Controls & Scrubber */}
             <div className="flex flex-col items-center max-w-[40%] w-full gap-2">
                 <div className="flex items-center gap-6">
                     <button className={`text-[#B3B3B3] hover:text-white ${isShuffling ? 'text-[#1DB954]' : ''}`}><Shuffle size={16} /></button>
                     <button onClick={prevSong} className="text-[#B3B3B3] hover:text-white"><SkipBack size={20} fill="currentColor" /></button>
                     <button 
                        onClick={togglePlay}
                        className="w-8 h-8 bg-white rounded-full flex items-center justify-center hover:scale-105 transition-transform"
                     >
                        {isPlaying ? <Pause size={16} fill="black" className="text-black" /> : <Play size={16} fill="black" className="ml-0.5 text-black" />}
                     </button>
                     <button onClick={nextSong} className="text-[#B3B3B3] hover:text-white"><SkipForward size={20} fill="currentColor" /></button>
                     <button className="text-[#B3B3B3] hover:text-white"><Repeat size={16} /></button>
                 </div>

                 <div className="flex items-center gap-2 w-full max-w-[600px] text-xs font-mono text-[#B3B3B3]">
                     <span>{formatTime(progress)}</span>
                     <div className="relative h-1 flex-1 bg-[#4D4D4D] rounded-full group cursor-pointer">
                          <div 
                            className="absolute left-0 top-0 bottom-0 bg-white group-hover:bg-[#1DB954] rounded-full" 
                            style={{ width: `${(progress / (duration || 1)) * 100}%` }}
                          ></div>
                          <input 
                            type="range" min="0" max={duration || 100} value={progress}
                            onChange={handleSeek} 
                            onMouseDown={() => setIsDragging(true)} 
                            onMouseUp={() => setIsDragging(false)}
                            className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                        />
                     </div>
                     <span>{formatTime(duration)}</span>
                 </div>
             </div>

             {/* Right: Volume & Extras */}
             <div className="flex items-center justify-end gap-3 w-[30%] min-w-[180px]">
                 <button className="text-[#B3B3B3] hover:text-white"><Mic2 size={16} /></button>
                 <button className="text-[#B3B3B3] hover:text-white"><ListMusic size={16} /></button>
                 <div className="flex items-center gap-2 w-24 group">
                     <Volume2 size={16} className="text-[#B3B3B3]" />
                     <div className="h-1 flex-1 bg-[#4D4D4D] rounded-full relative overflow-hidden">
                         <div className="absolute top-0 bottom-0 left-0 bg-white group-hover:bg-[#1DB954]" style={{ width: `${volume * 100}%` }}></div>
                         <input 
                            type="range" min="0" max="1" step="0.01" value={volume} 
                            onChange={(e) => setVolume(parseFloat(e.target.value))}
                            className="absolute inset-0 opacity-0 cursor-pointer"
                         />
                     </div>
                 </div>
                 <button onClick={() => setFullScreen(true)} className="text-[#B3B3B3] hover:text-white"><Maximize2 size={16} /></button>
             </div>
        </div>

        {/* --- MOBILE: Floating Pill & Full Screen Overlay --- */}
        <AnimatePresence>
            {!isFullScreen && (
                <motion.div 
                    initial={{ y: 20, opacity: 0 }}
                    animate={{ y: 0, opacity: 1 }}
                    exit={{ y: 20, opacity: 0 }}
                    onClick={() => setFullScreen(true)}
                    className="md:hidden fixed bottom-[68px] left-2 right-2 h-[56px] bg-[#222] rounded-md flex items-center px-3 gap-3 shadow-lg z-[150] cursor-pointer"
                >
                    <img src={imageUrl} className="h-10 w-10 rounded bg-[#333] object-cover" alt="" />
                    <div className="flex-1 min-w-0 flex flex-col justify-center">
                        <span className="text-white font-bold text-sm truncate">{currentSong.name}</span>
                        <span className="text-[#B3B3B3] text-xs truncate">{primaryArtistName}</span>
                    </div>
                    <div className="flex items-center gap-4 pr-1">
                        <button onClick={(e) => { e.stopPropagation(); toggleLike(currentSong); }}>
                             <Heart size={24} fill={isLiked ? "#1DB954" : "none"} className={isLiked ? "text-[#1DB954]" : "text-white"} />
                        </button>
                        <button onClick={(e) => { e.stopPropagation(); togglePlay(); }}>
                             {isPlaying ? <Pause size={24} fill="white" /> : <Play size={24} fill="white" />}
                        </button>
                    </div>
                    {/* Progress Bar Bottom */}
                    <div className="absolute bottom-0 left-1 right-1 h-[2px] bg-white/10 rounded-full overflow-hidden">
                        <div className="h-full bg-white rounded-full" style={{ width: `${(progress / (duration || 1)) * 100}%` }}></div>
                    </div>
                </motion.div>
            )}

            {isFullScreen && (
                 <motion.div 
                    initial={{ y: "100%" }}
                    animate={{ y: 0 }}
                    exit={{ y: "100%" }}
                    transition={{ type: "tween", ease: "circOut", duration: 0.25 }}
                    className="fixed inset-0 z-[200] bg-gradient-to-b from-[#404040] to-[#121212] flex flex-col pb-safe-bottom"
                >
                    {/* Header */}
                    <div className="flex items-center justify-between p-6 pt-safe-top">
                        <button onClick={() => setFullScreen(false)}><ChevronDown size={28} /></button>
                        <span className="text-xs font-bold tracking-widest uppercase text-white/70">Now Playing</span>
                        <button><Share2 size={24} /></button>
                    </div>

                    {/* Art */}
                    <div className="flex-1 flex items-center justify-center p-8">
                        <img src={imageUrl} className="w-full aspect-square object-cover rounded shadow-2xl" alt="" />
                    </div>

                    {/* Info */}
                    <div className="px-8 flex items-center justify-between mb-8">
                        <div className="flex flex-col overflow-hidden">
                            <h2 className="text-2xl font-bold text-white truncate">{currentSong.name}</h2>
                            <span className="text-lg text-[#B3B3B3] truncate">{primaryArtistName}</span>
                        </div>
                        <button onClick={() => toggleLike(currentSong)}>
                             <Heart size={28} fill={isLiked ? "#1DB954" : "none"} className={isLiked ? "text-[#1DB954]" : "text-white"} />
                        </button>
                    </div>

                    {/* Scrubber */}
                    <div className="px-8 mb-4">
                        <div className="relative h-1 w-full bg-[#555] rounded-full group">
                             <div className="absolute left-0 top-0 bottom-0 bg-white rounded-full" style={{ width: `${(progress / (duration || 1)) * 100}%` }}></div>
                             <input 
                                type="range" min="0" max={duration || 100} value={progress}
                                onChange={handleSeek}
                                className="absolute inset-0 opacity-0"
                             />
                        </div>
                        <div className="flex justify-between text-xs text-[#B3B3B3] mt-2 font-mono">
                            <span>{formatTime(progress)}</span>
                            <span>{formatTime(duration)}</span>
                        </div>
                    </div>

                    {/* Controls */}
                    <div className="flex items-center justify-between px-8 mb-10">
                        <button><Shuffle size={24} className={isShuffling ? "text-[#1DB954]" : "text-white"} /></button>
                        <button onClick={prevSong}><SkipBack size={32} fill="currentColor" /></button>
                        <button 
                            onClick={togglePlay} 
                            className="w-16 h-16 bg-white rounded-full flex items-center justify-center hover:scale-105 active:scale-95 transition-transform"
                        >
                            {isPlaying ? <Pause size={32} fill="black" className="text-black" /> : <Play size={32} fill="black" className="ml-1 text-black" />}
                        </button>
                        <button onClick={nextSong}><SkipForward size={32} fill="currentColor" /></button>
                        <button><Repeat size={24} /></button>
                    </div>
                </motion.div>
            )}
        </AnimatePresence>

        {downloadSong && (
            <DownloadQualityModal song={downloadSong} onClose={() => setDownloadSong(null)} />
        )}
    </>
  );
};

