  const lines = [
    "Yeah, we vibing all night long",
    "Can you feel the rhythm in your soul?",
    "Lights are flashing, world is spinning",
    "Just you and me, losing control",
    "Take my hand, let's fly away",
    "Nothing matters but today",
    "Music playing, hearts are beating",
    "In this moment, time is fleeting",
    "(Instrumental Break)",
    "Do you remember how it started?",
    "We were young and broken hearted",
    "Now we're here, standing tall",
    "Catch me, catch me if I fall",
    "Colors bursting in the sky",
    "Don't you ever say goodbye",
    "This is forever, this is real",
    "Tell me exactly how you feel"
  ];

  const step = duration / lines.length;
  return lines.map((text, i) => ({
    time: i * step,
    text
  }));
};

