         >
             {currentUser && currentUser.image ? (
                 <img src={currentUser.image} alt="Profile" className="w-full h-full object-cover" />
             ) : (
                 <span className="font-bold">{currentUser ? currentUser.name.charAt(0).toUpperCase() : <UserCircle size={20} />}</span>
             )}
         </div>

         <div className="flex items-center gap-2 overflow-x-auto no-scrollbar mask-linear-fade">
             {!isOfflineMode && (
                <>
                    <button className="px-3 py-1 bg-white text-black rounded-full text-xs font-bold transition-transform active:scale-95">All</button>
                    <button className="px-3 py-1 bg-[#2A2A2A] text-white rounded-full text-xs font-bold hover:bg-[#333] active:scale-95">Music</button>
                    <button className="px-3 py-1 bg-[#2A2A2A] text-white rounded-full text-xs font-bold hover:bg-[#333] active:scale-95">Podcasts</button>
