import React, { useState, useEffect, useRef } from 'react';
import { Search as SearchIcon, ArrowLeft, X, Loader2, CheckCircle2, PlusCircle, MoreHorizontal } from 'lucide-react';
import { api, getImageUrl } from '../services/api';
import { Song, Album, Artist } from '../types';
import { usePlayerStore } from '../store/playerStore';
import { useNavigate } from 'react-router-dom';
import { motion } from 'framer-motion';

const BROWSE_CATEGORIES = [
  { title: "Podcasts", color: "bg-[#006450]" },
  { title: "Live Events", color: "bg-[#8400E7]" },
  { title: "Made For You", color: "bg-[#1E3264]" },
  { title: "New Releases", color: "bg-[#E8115B]" },
  { title: "Hindi", color: "bg-[#E13300]" },
  { title: "Punjabi", color: "bg-[#B02897]" },
  { title: "Tamil", color: "bg-[#503750]" },
  { title: "Charts", color: "bg-[#8D67AB]" },
  { title: "Pop", color: "bg-[#148A08]" },
  { title: "Indie", color: "bg-[#E91429]" },
  { title: "Trending", color: "bg-[#B02897]" },
];

const containerVariants = {
  hidden: { opacity: 0 },
  visible: { opacity: 1, transition: { staggerChildren: 0.05 } }
};

const itemVariants = {
  hidden: { opacity: 0, scale: 0.9 },
  visible: { opacity: 1, scale: 1 }
};

export const Search: React.FC = () => {
  const [query, setQuery] = useState('');
  const [results, setResults] = useState<{ songs: Song[], albums: Album[], artists: Artist[] }>({ songs: [], albums: [], artists: [] });
  const [isLoading, setIsLoading] = useState(false);
  const [isFocused, setIsFocused] = useState(false);

  const { playSong, likedSongs, toggleLike } = usePlayerStore();
  const navigate = useNavigate();
  const abortControllerRef = useRef<AbortController | null>(null);

  useEffect(() => {
    if (abortControllerRef.current) abortControllerRef.current.abort();
    if (!query.trim()) {
        setResults({ songs: [], albums: [], artists: [] });
        setIsLoading(false);
        return;
    }

    setIsLoading(true);
    const timer = setTimeout(async () => {
        abortControllerRef.current = new AbortController();
        try {
           const [songs] = await Promise.all([api.searchSongs(query)]);
           if (!abortControllerRef.current?.signal.aborted) {
               setResults({ songs, albums: [], artists: [] });
           }
        } catch (e: any) {
            if (e.name !== 'AbortError') console.error(e);
        } finally {
            if (!abortControllerRef.current?.signal.aborted) setIsLoading(false);
        }
    }, 300);
    return () => clearTimeout(timer);
  }, [query]);

  const ResultSkeleton = () => (
      <div className="flex items-center gap-3 px-4 py-3 animate-pulse">
          <div className="w-12 h-12 bg-white/10 rounded-md shrink-0"></div>
          <div className="flex-1 space-y-2 py-1">
              <div className="h-4 bg-white/10 rounded w-1/3"></div>
              <div className="h-3 bg-white/5 rounded w-1/4"></div>
          </div>
      </div>
  );

  return (
    <div className="flex flex-col min-h-full pb-32 bg-[#121212]">

      {/* Sticky Search Header */}
      <div className="sticky top-0 bg-[#121212] z-40 px-4 py-3 border-b border-transparent shadow-sm">
         <div className="flex items-center gap-3">
             <button onClick={() => navigate(-1)} className="text-white hover:bg-white/10 p-2 rounded-full transition-colors md:hidden">
                <ArrowLeft size={24} />
             </button>

             <div className={`flex-1 relative group transition-all duration-300 ${isFocused ? 'scale-[1.01]' : 'scale-100'}`}>
                <SearchIcon size={20} className={`absolute left-3.5 top-1/2 -translate-y-1/2 transition-colors ${isFocused ? 'text-white' : 'text-[#777]'}`} />
                <input 
                  type="text"
                  className="w-full bg-[#242424] hover:bg-[#2a2a2a] focus:bg-[#1f1f1f] text-white rounded-full py-3.5 pl-11 pr-11 outline-none font-medium placeholder-[#777] transition-colors"
                  placeholder="What do you want to listen to?"
                  value={query}
                  onChange={(e) => setQuery(e.target.value)}
                  onFocus={() => setIsFocused(true)}
                  onBlur={() => setIsFocused(false)}
                />
                {(query || isLoading) && (
                    <div className="absolute right-3.5 top-1/2 -translate-y-1/2">
                         {isLoading ? <Loader2 size={18} className="text-[#1DB954] animate-spin" /> : 
                             <button onClick={() => setQuery('')}><X size={18} className="text-[#777] hover:text-white" /></button>
                         }
                    </div>
                )}
             </div>
         </div>
      </div>

      {/* Browse All */}
      {!query && (
         <div className="p-4 pt-6">
             <h2 className="text-white font-bold text-lg mb-4">Browse all</h2>
             <motion.div variants={containerVariants} initial="hidden" animate="visible" className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-5 gap-4">
                 {BROWSE_CATEGORIES.map((cat, idx) => (
                     <motion.div 
                        key={idx} 
                        variants={itemVariants}
                        whileHover={{ scale: 1.02 }}
                        whileTap={{ scale: 0.98 }}
                        className={`${cat.color} aspect-[1.6/1] rounded-lg p-4 relative overflow-hidden cursor-pointer hover:opacity-90`}
                        onClick={() => setQuery(cat.title)} 
                     >
                         <h3 className="text-white font-bold text-xl relative z-10 leading-tight">{cat.title}</h3>
                         <div className="absolute -bottom-2 -right-4 w-20 h-20 bg-black/20 rotate-[25deg] shadow-lg rounded-md"></div>
                     </motion.div>
                 ))}
             </motion.div>
         </div>
      )}

      {/* Loading Skeleton */}
      {isLoading && !results.songs.length && <div className="flex flex-col w-full pt-2">{[1,2,3,4,5].map(i => <ResultSkeleton key={i} />)}</div>}

      {/* Results */}
      {query && (
        <div className="flex flex-col w-full pb-8">
            {results.songs.map((song) => {
                 const isLiked = likedSongs.some(s => s.id === song.id);
                 return (
                     <div 
                        key={song.id} 
                        className="flex items-center gap-3 px-4 py-2.5 hover:bg-[#2A2A2A] cursor-pointer group transition-colors rounded-md mx-2" 
                        onClick={() => playSong(song, results.songs)}
                     >
                         <img src={getImageUrl(song.image)} className="w-12 h-12 rounded-[4px] object-cover shadow-sm shrink-0" alt="" />
                         <div className="flex-1 min-w-0 flex flex-col justify-center gap-0.5">
                             <div className={`font-medium truncate text-[15px] ${isLiked ? 'text-[#1DB954]' : 'text-white'}`}>{song.name}</div>
                             <div className="text-[#B3B3B3] text-sm truncate flex items-center gap-1">
                                {song.name.toLowerCase().includes('explicit') && <span className="bg-[#B3B3B3] text-black text-[9px] px-1 rounded-[2px] font-bold">E</span>}
                                <span>{song.artists?.primary?.[0]?.name || "Unknown"}</span>
                             </div>
                         </div>
                         <button onClick={(e) => { e.stopPropagation(); toggleLike(song); }} className="text-[#B3B3B3] hover:text-white p-2">
                            {isLiked ? <CheckCircle2 size={20} className="text-[#1DB954]" /> : <PlusCircle size={20} />}
                         </button>
                         <button className="text-[#B3B3B3] hover:text-white p-2"><MoreHorizontal size={20} /></button>
                     </div>
                 );
            })}

            {!isLoading && results.songs.length === 0 && (
                <div className="flex flex-col items-center justify-center pt-20 text-[#777]">
                    <div className="w-16 h-16 bg-[#1A1A1A] rounded-full flex items-center justify-center mb-4"><SearchIcon size={32} /></div>
                    <h3 className="text-white font-bold">No results found</h3>
                </div>
            )}
        </div>
      )}
    </div>
  );
};

