import { UserPlaylist } from '../types';

export const PlaylistDetails: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const { userPlaylists, playSong, currentSong, isPlaying, removePlaylist } = usePlayerStore();

  const [viewPlaylist, setViewPlaylist] = useState<UserPlaylist | null>(null);
  const [scrollOpacity, setScrollOpacity] = useState(0);
  const isMyPlaylist = userPlaylists.some(p => p.id === id);

  useEffect(() => {
    const handleScroll = () => setScrollOpacity(Math.min(window.scrollY / 200, 1));
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  useEffect(() => {
      const load = async () => {
          const local = userPlaylists.find(p => p.id === id);
          if (local) setViewPlaylist(local);
          else if (id) {
              const pub = await authService.getPublicPlaylist(id);
              if (pub) setViewPlaylist(pub);
          }
      };
      load();
  }, [id, userPlaylists]);

  if (!viewPlaylist) return <div className="flex h-full items-center justify-center bg-[#121212] text-white">Loading...</div>;

  return (
    <div className="min-h-full pb-32 bg-[#121212] relative isolate">
      <div className="absolute top-0 left-0 right-0 h-[500px] bg-gradient-to-b from-[#444] to-[#121212] -z-10" />

