          <div className="flex items-center gap-4">
              <button onClick={() => navigate(-1)} className="w-8 h-8 rounded-full bg-black/40 hover:bg-black/60 flex items-center justify-center text-white">
                 <ArrowLeft size={20} />
              </button>
              <span className="font-bold text-lg text-white transition-opacity duration-300" style={{ opacity: scrollOpacity }}>{viewPlaylist.title}</span>
          </div>
          {isMyPlaylist && (
             <button onClick={() => { removePlaylist(viewPlaylist.id); navigate('/library'); }} className="text-white/70 hover:text-white"><Trash2 size={20} /></button>
          )}
      </div>

      <div className="flex flex-col md:flex-row items-end gap-6 p-6 md:p-10 -mt-[60px] pt-[70px]">
        <div className="w-[200px] h-[200px] shadow-[0_20px_50px_rgba(0,0,0,0.5)] bg-[#282828] flex items-center justify-center rounded-md overflow-hidden shrink-0">
             {viewPlaylist.image?.[0] ? <img src={getImageUrl(viewPlaylist.image)} className="w-full h-full object-cover" /> : <Music size={60} className="text-white/20" />}
        </div>
        <div className="flex flex-col gap-2 mb-2 w-full min-w-0">
            <span className="uppercase text-xs font-bold tracking-widest text-white">Playlist</span>
            <h1 className="text-4xl md:text-7xl font-black text-white tracking-tighter leading-none line-clamp-2">{viewPlaylist.title}</h1>
            <p className="text-white/70 text-sm font-medium line-clamp-1">{viewPlaylist.description}</p>
            <div className="flex items-center gap-1.5 text-sm font-bold text-white mt-4">
                <span className="hover:underline cursor-pointer">{viewPlaylist.creator ? 'User' : 'You'}</span>
                <span className="text-white/70">• {viewPlaylist.songs.length} songs</span>
            </div>
        </div>
      </div>

      <div className="px-6 md:px-10 py-6 flex items-center gap-6 bg-[#121212]/30 backdrop-blur-sm">
         {viewPlaylist.songs.length > 0 && (
             <button 
                onClick={() => playSong(viewPlaylist.songs[0], viewPlaylist.songs)}
                className="w-14 h-14 bg-[#1DB954] hover:bg-[#1ed760] rounded-full flex items-center justify-center hover:scale-105 active:scale-95 transition-all shadow-lg"
