import React, { useEffect, useState } from 'react';
import { useParams, useLocation, useNavigate } from 'react-router-dom';
import { api, getImageUrl } from '../services/api';
import { Artist, Song, Album } from '../types';
import { usePlayerStore } from '../store/playerStore';
import { Play, Pause, CheckCircle2, PlusCircle, ArrowLeft, MoreHorizontal } from 'lucide-react';

export const ArtistDetails: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const location = useLocation();
  const navigate = useNavigate();
  const [artist, setArtist] = useState<Artist | null>(location.state?.artist || null);
  const [songs, setSongs] = useState<Song[]>([]);
  const [albums, setAlbums] = useState<Album[]>([]);
  const [loading, setLoading] = useState(!artist);
  const { playSong, currentSong, isPlaying, toggleLike, likedSongs } = usePlayerStore();
  const [scrollOpacity, setScrollOpacity] = useState(0);

  useEffect(() => {
    const handleScroll = () => setScrollOpacity(Math.min(window.scrollY / 200, 1));
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  useEffect(() => {
    const fetchData = async () => {
      let currentArtist = artist;
      if (!currentArtist && id) {
        try {
           const results = await api.searchArtists(id);
           if (results.length > 0) {
             currentArtist = results[0];
             setArtist(currentArtist);
           }
        } catch (e) { console.error(e); }
      }
      if (currentArtist) {
        setLoading(true);
        try {
            const [trackResults, albumResults] = await Promise.all([
                api.searchSongs(currentArtist.name),
                api.searchAlbums(currentArtist.name)
            ]);
            setSongs(trackResults);
            setAlbums(albumResults);
        } catch (e) { console.error(e); } finally { setLoading(false); }
      } else setLoading(false);
    };
    fetchData();
  }, [id, artist]);

  if (loading) return <div className="flex h-screen items-center justify-center bg-[#121212]"><div className="w-8 h-8 border-2 border-white border-t-transparent rounded-full animate-spin"></div></div>;
  if (!artist) return null;

  const imageUrl = getImageUrl(artist.image);

  return (
    <div className="min-h-full pb-32 bg-[#121212] text-white relative isolate">

        {/* Sticky Header */}
        <div 
            className="fixed top-0 left-0 right-0 z-40 transition-colors duration-200 flex items-center justify-between px-6 py-3"
            style={{ backgroundColor: `rgba(18, 18, 18, ${scrollOpacity})` }}
        >
            <button onClick={() => navigate(-1)} className="p-2 rounded-full bg-black/40 hover:bg-black/60 text-white">
                <ArrowLeft size={20} />
            </button>
            <span 
                className="font-bold text-lg transition-opacity duration-300"
                style={{ opacity: scrollOpacity }}
            >
                {artist.name}
            </span>
            <button className="p-2 rounded-full bg-black/40 hover:bg-black/60 text-white">
                <MoreHorizontal size={20} />
            </button>
        </div>

        {/* Hero Image */}
        <div className="relative w-full h-[400px] z-0">
            <div className="absolute inset-0 bg-gradient-to-b from-transparent via-black/20 to-[#121212] z-10"></div>
            <img src={imageUrl} alt={artist.name} className="w-full h-full object-cover object-center" />
            <div className="absolute bottom-0 left-0 p-8 z-20 w-full">
                 <div className="flex items-center gap-2 mb-2">
                     <CheckCircle2 size={24} className="text-[#3d91f4] fill-white bg-white rounded-full border-none" />
                     <span className="text-sm font-medium tracking-wide">Verified Artist</span>
                 </div>
                 <h1 className="text-5xl md:text-8xl font-black text-white drop-shadow-xl tracking-tighter">{artist.name}</h1>
                 <p className="text-white/90 mt-4 font-bold text-base">10,230,129 monthly listeners</p>
            </div>
        </div>

        <div className="px-6 py-6 flex items-center gap-4 bg-[#121212] relative z-20">
             <button 
                 onClick={() => songs.length > 0 && playSong(songs[0], songs)}
                 className="w-14 h-14 bg-[#1DB954] hover:bg-[#1ed760] rounded-full flex items-center justify-center hover:scale-105 active:scale-95 transition-transform shadow-lg"
             >
                 {isPlaying && currentSong?.artists?.primary?.[0]?.name === artist.name ? <Pause size={28} fill="black" className="text-black" /> : <Play size={28} fill="black" className="text-black ml-1" />}
             </button>
             <button className="px-6 py-2 rounded-full border border-white/30 text-sm font-bold hover:border-white hover:scale-105 transition-all">Follow</button>
        </div>

        <div className="px-6 pb-8 bg-[#121212] relative z-20">
            <h2 className="text-2xl font-bold mb-4">Popular</h2>
            <div className="flex flex-col">
                {songs.slice(0, 5).map((song, index) => {
                    const isCurrent = currentSong?.id === song.id;
                    const isSongLiked = likedSongs.some(s => s.id === song.id);

                    return (
                        <div 
                            key={song.id}
                            onClick={() => playSong(song, songs)}
                            className={`flex items-center gap-4 p-3 rounded-md cursor-pointer transition-colors ${isCurrent ? 'bg-white/10' : 'hover:bg-[#2A2A2A]'}`}
                        >
                            <span className="w-4 text-center text-sm font-mono text-[#B3B3B3]">{index + 1}</span>
                            <img src={getImageUrl(song.image)} className="w-10 h-10 rounded object-cover" alt="" />
                            <div className="flex-1 min-w-0">
                                <div className={`font-bold truncate text-[16px] ${isCurrent ? 'text-[#1DB954]' : 'text-white'}`}>{song.name}</div>
                                <div className="text-xs text-[#B3B3B3] truncate">{song.artists.primary[0]?.name}</div>
                            </div>
                            <span className="text-xs text-[#B3B3B3] font-mono hidden md:block">
                                {(parseInt(song.duration) / 60).toFixed(0)}:{(parseInt(song.duration) % 60).toString().padStart(2, '0')}
                            </span>
                            <button onClick={(e) => { e.stopPropagation(); toggleLike(song); }} className={`${isSongLiked ? 'text-[#1DB954]' : 'text-[#B3B3B3] hover:text-white'}`}>
                                {isSongLiked ? <CheckCircle2 size={18} /> : <PlusCircle size={18} />}
                            </button>
                        </div>
                    );
                })}
            </div>
        </div>

        {albums.length > 0 && (
            <div className="px-6 pb-8 bg-[#121212] relative z-20">
                <h2 className="text-2xl font-bold mb-4">Discography</h2>
