  const [isDragging, setIsDragging] = useState(false);

  const [downloadSong, setDownloadSong] = useState<Song | null>(null);
  const [isMoreMenuOpen, setIsMoreMenuOpen] = useState(false);

  // New States for enhanced features
  const [sleepTimerId, setSleepTimerId] = useState<number | null>(null);
  const [toastMessage, setToastMessage] = useState<string | null>(null);

  const [touchStart, setTouchStart] = useState<{x: number, y: number} | null>(null);

  const isLiked = currentSong ? likedSongs.some(s => s.id === currentSong.id) : false;
  const isDownloaded = currentSong ? downloadedSongIds.includes(currentSong.id) : false;

  // Extract color from image
  useEffect(() => {
    if (!currentSong) return;
    const imgUrl = getImageUrl(currentSong.image);
    const img = new Image();
    img.crossOrigin = "Anonymous";
    img.src = imgUrl;

    img.onload = () => {
      try {
        const canvas = document.createElement('canvas');
        const ctx = canvas.getContext('2d');
        if (!ctx) return;
        canvas.width = 1; 
        canvas.height = 1;
        ctx.drawImage(img, 0, 0, 1, 1);
        const [r, g, b] = ctx.getImageData(0, 0, 1, 1).data;
        setDominantColor(`rgb(${Math.max(20, r - 30)},${Math.max(20, g - 30)},${Math.max(20, b - 30)})`);
      } catch (e) {
        setDominantColor('#181818'); 
      }
    };
    img.onerror = () => setDominantColor('#181818');
  }, [currentSong?.id]);

  // MEDIA SESSION API INTEGRATION (Notification Poster)
  useEffect(() => {
    if (!currentSong || !('mediaSession' in navigator)) return;

    const artistName = currentSong.artists?.primary?.[0]?.name || "Unknown";
    // Get the largest image for the notification poster
    const hqImage = currentSong.image[currentSong.image.length - 1]?.url || getImageUrl(currentSong.image);

    navigator.mediaSession.metadata = new MediaMetadata({
      title: currentSong.name,
      artist: artistName,
      album: currentSong.album?.name || "Single",
      artwork: [
          { src: hqImage, sizes: '96x96', type: 'image/jpeg' },
          { src: hqImage, sizes: '128x128', type: 'image/jpeg' },
          { src: hqImage, sizes: '192x192', type: 'image/jpeg' },
          { src: hqImage, sizes: '256x256', type: 'image/jpeg' },
          { src: hqImage, sizes: '384x384', type: 'image/jpeg' },
          { src: hqImage, sizes: '512x512', type: 'image/jpeg' },
      ]
    });

    navigator.mediaSession.setActionHandler('play', () => setIsPlaying(true));
    navigator.mediaSession.setActionHandler('pause', () => setIsPlaying(false));
    navigator.mediaSession.setActionHandler('previoustrack', prevSong);
    navigator.mediaSession.setActionHandler('nexttrack', nextSong);
    navigator.mediaSession.setActionHandler('seekto', (details) => {
        if (audioRef.current && details.seekTime !== undefined) {
            audioRef.current.currentTime = details.seekTime;
            setProgress(details.seekTime);
        }
    });
  }, [currentSong, setIsPlaying, prevSong, nextSong]);

  // Sync Playback State with Media Session
  useEffect(() => {
      if ('mediaSession' in navigator) {
          navigator.mediaSession.playbackState = isPlaying ? "playing" : "paused";
      }
  }, [isPlaying]);

  // Audio Source Logic
  useEffect(() => {
    if (!currentSong || !audioRef.current) return;

    const setAudioSource = async () => {
        let url = '';
        if (isOfflineMode || downloadedSongIds.includes(currentSong.id)) {
            const blobUrl = await getOfflineAudioUrl(currentSong.id);
            if (blobUrl) url = blobUrl;
            else if (isOfflineMode) { setIsPlaying(false); return; }
        }
        if (!url && !isOfflineMode) {
             url = getAudioUrl(currentSong.downloadUrl, streamingQuality);
        }
        if (url && audioRef.current && audioRef.current.src !== url) {
            const wasPlaying = isPlaying;
            audioRef.current.src = url;
            audioRef.current.load();
            if (wasPlaying) {
                 audioRef.current.play().catch(() => setIsPlaying(false));
            }
        }
    };
    setAudioSource();
  }, [currentSong?.id, streamingQuality, isOfflineMode]);

  useEffect(() => {
    const audio = audioRef.current;
    if (!audio) return;
    if (isPlaying && audio.paused) audio.play().catch(e => console.warn("Play interrupted", e));
    else if (!isPlaying && !audio.paused) audio.pause();
  }, [isPlaying]);

  const handleTimeUpdate = () => {
    if (audioRef.current && !isDragging) {
      const currentTime = audioRef.current.currentTime;
      const duration = audioRef.current.duration || 0;

      setProgress(currentTime);
      setDuration(duration);

      if ('mediaSession' in navigator && duration > 0 && !isNaN(duration)) {
          try {
            navigator.mediaSession.setPositionState({
                duration: duration,
                playbackRate: audioRef.current.playbackRate,
                position: currentTime
            });
          } catch (e) {}
      }
    }
  };

  const handleSeek = (e: React.ChangeEvent<HTMLInputElement>) => {
    const time = parseFloat(e.target.value);
    setProgress(time);
    if (audioRef.current) audioRef.current.currentTime = time;
  };

  const formatTime = (seconds: number) => {
    if (!seconds || isNaN(seconds)) return "-:--";
    const mins = Math.floor(seconds / 60);
    const secs = Math.floor(seconds % 60);
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  // Helper to show temporary messages
  const showToast = (msg: string) => {
      setToastMessage(msg);
      setTimeout(() => setToastMessage(null), 2500);
  };

  // --- ACTIONS FOR MORE MENU ---
  const handleAddToQueue = () => {
      if(currentSong) {
          addToQueue(currentSong);
          showToast("Added to queue");
          setIsMoreMenuOpen(false);
      }
  };

  const handleShare = async () => {
      if(!currentSong) return;
      const shareData = {
          title: currentSong.name,
          text: `Listen to ${currentSong.name} by ${currentSong.artists.primary[0].name}`,
          url: window.location.href // Simplified for demo
      };

      if (navigator.share) {
          try {
              await navigator.share(shareData);
          } catch(e) { console.log(e); }
      } else {
          navigator.clipboard.writeText(shareData.url);
          showToast("Link copied to clipboard");
      }
      setIsMoreMenuOpen(false);
  };

  const handleSleepTimer = () => {
      if (sleepTimerId) {
          clearTimeout(sleepTimerId);
          setSleepTimerId(null);
          showToast("Sleep timer turned off");
      } else {
          // Set for 30 mins
          const id = window.setTimeout(() => {
              setIsPlaying(false);
              setSleepTimerId(null);
          }, 30 * 60 * 1000); 
          setSleepTimerId(id);
          showToast("Sleep timer set for 30 minutes");
      }
      setIsMoreMenuOpen(false);
  };

  const handleGoToRadio = () => {
      if(currentSong) {
          navigate(`/search`);
          // Ideally navigate to a search with "Radio" query
          setTimeout(() => {
             // Mock navigation
          }, 100);
      }
      setIsMoreMenuOpen(false);
  };

  const handleTouchStart = (e: React.TouchEvent) => {
    setTouchStart({ x: e.targetTouches[0].clientX, y: e.targetTouches[0].clientY });
  };

  const handleTouchEnd = (e: React.TouchEvent) => {
    if (!touchStart) return;
    const touchEndX = e.changedTouches[0].clientX;
    const touchEndY = e.changedTouches[0].clientY;
    const diffX = touchStart.x - touchEndX;
    const diffY = touchStart.y - touchEndY;

    if (Math.abs(diffX) > 50 && Math.abs(diffX) > Math.abs(diffY)) {
      if (diffX > 0) nextSong();
      else prevSong();
    }
    if (diffY < -80 && Math.abs(diffY) > Math.abs(diffX) && !isMoreMenuOpen) {
        setFullScreen(false);
    }
    setTouchStart(null);
  };

  if (!currentSong) return null;

  const imageUrl = getImageUrl(currentSong.image);
  const primaryArtistName = currentSong.artists?.primary?.[0]?.name || "Unknown";

  return (
    <>
        <audio 
            ref={audioRef}
            preload="auto"
            onTimeUpdate={handleTimeUpdate}
            onEnded={nextSong}
            onWaiting={() => setIsBuffering(true)}
            onPlaying={() => setIsBuffering(false)}
            onCanPlay={() => setIsBuffering(false)}
            onPause={() => {
                if (isPlaying && !isBuffering && audioRef.current?.paused) setIsPlaying(false);
            }}
            onPlay={() => !isPlaying && setIsPlaying(true)}
        />

        <AnimatePresence mode="wait">
            {isFullScreen ? (
                <motion.div 
                    key="full-player"
                    initial={{ y: "100%" }}
                    animate={{ y: 0 }}
                    exit={{ y: "100%" }}
                    transition={{ type: "spring", damping: 30, stiffness: 300, mass: 0.8 }}
                    className="fixed inset-0 z-[200] flex flex-col bg-[#121212] isolate overflow-hidden"
                    onClick={(e) => e.stopPropagation()}
                    onTouchStart={handleTouchStart}
                    onTouchEnd={handleTouchEnd}
                >
                    {/* Background */}
                    <div 
                        className="absolute inset-0 z-[-1]"
                        style={{ 
                            background: `linear-gradient(to bottom, ${dominantColor}, #121212)`,
                        }}
                    />

                    {/* FULL PLAYER CONTENT */}
                    <div className="relative z-10 flex flex-col h-full px-6 pt-safe-top pb-safe-bottom">

                        {/* Header */}
                        <div className="flex items-center justify-between h-16 shrink-0 mt-2">
                            <button onClick={() => setFullScreen(false)} className="p-2 -ml-2 rounded-full hover:bg-white/10 shrink-0">
                                <ChevronDown size={28} className="text-white" />
                            </button>
                            <span className="text-[11px] font-bold tracking-[0.15em] uppercase text-white/70">
                                Now Playing
                            </span>
                            <button onClick={() => setIsMoreMenuOpen(true)} className="p-2 -mr-2 rounded-full hover:bg-white/10 shrink-0">
                                <MoreHorizontal size={24} className="text-white" />
                            </button>
                        </div>

                        {/* Main Artwork Area */}
                        <div className="flex-1 flex flex-col justify-center min-h-0 relative my-4">
                            <div className="relative w-full aspect-square max-w-[340px] mx-auto shadow-2xl rounded-xl overflow-hidden">
                                <img 
                                    src={imageUrl} 
                                    alt="Cover"
                                    className="w-full h-full object-cover"
                                />
                            </div>
                        </div>

                        {/* Info & Controls */}
                        <div className="flex flex-col gap-6 mb-10">
                            <div className="flex items-center justify-between">
                                <div className="flex flex-col overflow-hidden mr-4 min-w-0">
                                    <h2 className="text-2xl font-bold text-white truncate">
                                        {currentSong.name}
                                    </h2>
                                    <p className="text-lg text-white/70 truncate">
                                        {primaryArtistName}
                                    </p>
                                </div>
                                <button onClick={() => toggleLike(currentSong)} className="shrink-0">
                                    {isLiked ? <CheckCircle2 size={28} className="text-[#1DB954] fill-black" /> : <PlusCircle size={28} className="text-white/70" />}
                                </button>
                            </div>

                            {/* Scrubber */}
                            <div className="flex flex-col gap-2">
                                <div className="relative h-1 w-full bg-white/20 rounded-full group hover:h-1.5 transition-all">
                                     <div className="absolute left-0 top-0 bottom-0 bg-white rounded-full" style={{ width: `${(progress / (duration || 1)) * 100}%` }}>
                                        <div className="absolute right-0 top-1/2 -translate-y-1/2 w-3 h-3 bg-white rounded-full opacity-0 group-hover:opacity-100"></div>
                                     </div>
                                     <input 
                                        type="range" min="0" max={duration || 100} value={progress}
                                        onChange={handleSeek}
                                        onMouseDown={() => setIsDragging(true)}
                                        onTouchStart={() => setIsDragging(true)}
                                        onMouseUp={() => setIsDragging(false)}
                                        onTouchEnd={() => setIsDragging(false)}
                                        className="absolute inset-0 opacity-0 cursor-pointer"
                                    />
                                </div>
                                <div className="flex justify-between text-[11px] text-white/50 font-mono font-medium">
                                    <span>{formatTime(progress)}</span>
                                    <span>{formatTime(duration)}</span>
                                </div>
                            </div>

                            {/* Controls */}
                            <div className="flex items-center justify-between px-2">
                                <button className={`shrink-0 ${isShuffling ? 'text-[#1DB954]' : 'text-white/40'}`}><Shuffle size={20} /></button>
                                <button onClick={prevSong} className="shrink-0"><SkipBack size={32} className="text-white" fill="white" /></button>
                                <button 
                                    onClick={togglePlay}
                                    className="w-16 h-16 bg-white rounded-full flex items-center justify-center hover:scale-105 active:scale-95 transition-transform shrink-0"
                                >
                                    {isBuffering ? <Loader2 size={32} className="animate-spin text-black" /> : isPlaying ? <Pause size={32} fill="black" className="text-black" /> : <Play size={32} fill="black" className="ml-1 text-black" />}
                                </button>
                                <button onClick={nextSong} className="shrink-0"><SkipForward size={32} className="text-white" fill="white" /></button>
                                <button className="text-white/40 shrink-0"><Repeat size={20} /></button>
                            </div>

                            {/* Bottom Row */}
                            <div className="flex items-center justify-between px-4">
                                <button onClick={() => setDownloadSong(currentSong)} className={`shrink-0 ${isDownloaded ? 'text-[#1DB954]' : 'text-white/50'}`}>
                                    <Download size={22} />
                                </button>
                                <button className="text-white/50 shrink-0"><ListMusic size={22} /></button>
                            </div>
                        </div>
                    </div>

                    {/* Toast Notification */}
                    <AnimatePresence>
                        {toastMessage && (
                            <motion.div 
                                initial={{ opacity: 0, y: 20 }}
                                animate={{ opacity: 1, y: 0 }}
                                exit={{ opacity: 0, y: 20 }}
                                className="absolute bottom-32 left-1/2 -translate-x-1/2 z-[300] bg-white text-black px-6 py-3 rounded-full font-bold shadow-xl text-sm whitespace-nowrap"
                            >
                                {toastMessage}
                            </motion.div>
                        )}
                    </AnimatePresence>

                    {/* More Menu (Enhanced) */}
                    <AnimatePresence>
                        {isMoreMenuOpen && (
                            <motion.div 
                                initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
                                className="absolute inset-0 z-[250] bg-black/60 backdrop-blur-sm flex flex-col justify-end"
                                onClick={() => setIsMoreMenuOpen(false)}
                            >
                                <motion.div 
                                    initial={{ y: "100%" }} animate={{ y: 0 }} exit={{ y: "100%" }}
                                    transition={{ type: "tween", ease: "circOut", duration: 0.3 }}
                                    drag="y"
                                    dragConstraints={{ top: 0 }}
                                    dragElastic={{ top: 0, bottom: 0.2 }}
                                    onDragEnd={(_, info) => {
                                        if (info.offset.y > 100 || info.velocity.y > 100) {
                                            setIsMoreMenuOpen(false);
                                        }
                                    }}
                                    className="bg-[#242424] rounded-t-2xl flex flex-col max-h-[80vh] overflow-y-auto"
                                    onClick={e => e.stopPropagation()}
                                >
                                    {/* Drag Handle */}
                                    <div className="w-full flex justify-center pt-4 pb-2">
                                        <div className="w-10 h-1 bg-white/20 rounded-full"></div>
                                    </div>

                                    {/* Song Context Info */}
                                    <div className="flex items-center gap-3 px-6 pb-6 border-b border-white/5">
                                        <img src={getImageUrl(currentSong.image)} className="w-12 h-12 rounded-md object-cover shadow-lg" alt="" />
                                        <div>
                                            <div className="font-bold text-white text-[15px]">{currentSong.name}</div>
                                            <div className="text-sm text-white/60">{primaryArtistName}</div>
                                        </div>
                                    </div>

                                    {/* Menu Actions List */}
                                    <div className="flex flex-col py-2">

                                        <button onClick={() => { toggleLike(currentSong); setIsMoreMenuOpen(false); showToast(isLiked ? "Removed from Liked Songs" : "Added to Liked Songs"); }} className="flex items-center gap-4 px-6 py-3.5 hover:bg-white/5 active:bg-black/20 transition-colors">
                                            <Heart size={24} className={isLiked ? "text-[#1DB954] fill-[#1DB954]" : "text-white/80"} />
                                            <span className="text-white font-medium">{isLiked ? 'Liked' : 'Like'}</span>
                                        </button>

                                        <button onClick={handleAddToQueue} className="flex items-center gap-4 px-6 py-3.5 hover:bg-white/5 active:bg-black/20 transition-colors">
                                            <ListPlus size={24} className="text-white/80" />
                                            <span className="text-white font-medium">Add to queue</span>
                                        </button>

                                        <button onClick={handleShare} className="flex items-center gap-4 px-6 py-3.5 hover:bg-white/5 active:bg-black/20 transition-colors">
                                            <Share2 size={24} className="text-white/80" />
                                            <span className="text-white font-medium">Share</span>
                                        </button>

                                        <button onClick={() => navigate(`/artist/${currentSong.artists.primary[0].id}`, { state: { artist: currentSong.artists.primary[0] } })} className="flex items-center gap-4 px-6 py-3.5 hover:bg-white/5 active:bg-black/20 transition-colors">
                                            <User size={24} className="text-white/80" />
                                            <span className="text-white font-medium">View Artist</span>
                                        </button>

                                        <button onClick={() => navigate(`/album/${currentSong.album.id}`)} className="flex items-center gap-4 px-6 py-3.5 hover:bg-white/5 active:bg-black/20 transition-colors">
                                            <Disc size={24} className="text-white/80" />
                                            <span className="text-white font-medium">View Album</span>
                                        </button>

                                        <button onClick={handleSleepTimer} className="flex items-center gap-4 px-6 py-3.5 hover:bg-white/5 active:bg-black/20 transition-colors">
                                            <Moon size={24} className={sleepTimerId ? "text-[#1DB954]" : "text-white/80"} />
                                            <span className="text-white font-medium">{sleepTimerId ? 'Stop Sleep Timer' : 'Sleep Timer (30 mins)'}</span>
                                        </button>

                                        <button onClick={handleGoToRadio} className="flex items-center gap-4 px-6 py-3.5 hover:bg-white/5 active:bg-black/20 transition-colors">
                                            <Radio size={24} className="text-white/80" />
                                            <span className="text-white font-medium">Go to Song Radio</span>
                                        </button>

                                        <button onClick={() => showToast("Credits: Written by " + primaryArtistName)} className="flex items-center gap-4 px-6 py-3.5 hover:bg-white/5 active:bg-black/20 transition-colors">
                                            <Mic2 size={24} className="text-white/80" />
                                            <span className="text-white font-medium">Show credits</span>
                                        </button>

                                    </div>

                                    {/* Close Button at bottom */}
                                    <div className="p-4 mt-2">
                                        <button onClick={() => setIsMoreMenuOpen(false)} className="w-full py-3 font-bold text-white hover:scale-105 transition-transform">
                                            Close
                                        </button>
                                    </div>
                                </motion.div>
                            </motion.div>
                        )}
                    </AnimatePresence>
                </motion.div>
            ) : (
                <motion.div 
                    key="mini-player"
                    initial={{ y: 50, opacity: 0 }}
                    animate={{ y: 0, opacity: 1 }}
                    exit={{ y: 50, opacity: 0 }}
                    transition={{ type: "spring", stiffness: 400, damping: 30 }}
                    className="fixed bottom-[68px] md:bottom-4 left-2 right-2 md:left-1/2 md:-translate-x-1/2 md:w-[450px] h-[56px] z-[150] cursor-pointer isolate"
                    onClick={() => setFullScreen(true)}
                >
                    {/* Background */}
                    <div 
                        className="absolute inset-0 z-[-1] rounded-lg shadow-xl overflow-hidden"
                        style={{ backgroundColor: dominantColor }}
                    >
                         <div className="absolute inset-0 bg-black/20" />
                    </div>

                    <div className="flex items-center h-full px-2 gap-3">
                        {/* Image */}
                        <div className="h-10 w-10 shrink-0 rounded-[4px] overflow-hidden shadow-sm">
                            <img src={imageUrl} alt="" className="w-full h-full object-cover" />
                        </div>

                        {/* Text Info */}
                        <div className="flex-1 flex flex-col justify-center min-w-0 pr-2">
                            <span className="text-white font-bold text-xs truncate">
                                {currentSong.name}
                            </span>
                            <span className="text-white/70 text-[10px] truncate">
                                {primaryArtistName}
                            </span>
                        </div>

                        {/* Controls */}
                        <div className="flex items-center gap-1.5 pr-1 shrink-0">
                            {/* Like Button */}
                            <button onClick={(e) => { e.stopPropagation(); toggleLike(currentSong); }} className="shrink-0 p-1.5">
                                <Heart size={20} fill={isLiked ? "#1DB954" : "none"} className={isLiked ? "text-[#1DB954]" : "text-white"} />
                            </button>

                            {/* Previous Button (Hidden on very small screens if needed, but fitting here) */}
                            <button onClick={(e) => { e.stopPropagation(); prevSong(); }} className="shrink-0 p-1.5 text-white/90 hover:text-white">
                                <SkipBack size={22} fill="white" />
                            </button>

                            {/* Play/Pause Button */}
                            <button onClick={(e) => { e.stopPropagation(); togglePlay(); }} className="shrink-0 p-1.5">
                                {isBuffering ? (
                                    <Loader2 size={24} className="animate-spin text-white" />
                                ) : isPlaying ? (
                                    <Pause size={24} fill="white" className="text-white" />
                                ) : (
                                    <Play size={24} fill="white" className="text-white" />
                                )}
                            </button>

                            {/* Next Button */}
                            <button onClick={(e) => { e.stopPropagation(); nextSong(); }} className="shrink-0 p-1.5 text-white/90 hover:text-white">
                                <SkipForward size={22} fill="white" />
                            </button>
                        </div>
                    </div>

                    {/* Progress Bar (Mini only) */}
                    <div className="absolute bottom-0 left-1 right-1 h-[2px] bg-white/20 rounded-full overflow-hidden">
                        <div className="h-full bg-white rounded-full" style={{ width: `${(progress / (duration || 1)) * 100}%` }}></div>
                    </div>
                </motion.div>
            )}
        </AnimatePresence>

        {downloadSong && (
            <DownloadQualityModal song={downloadSong} onClose={() => setDownloadSong(null)} />
        )}
    </>
  );
};

import React, { useRef, useEffect, useState } from 'react';
import { Play, Pause, SkipBack, SkipForward, ChevronDown, MoreHorizontal, Download, ListMusic, Heart, Loader2, Shuffle, Repeat, PlusCircle, CheckCircle2, Disc, User, Share2, ListPlus, Radio, Mic2, Moon, Timer, X, Copy } from 'lucide-react';
import { usePlayerStore } from '../store/playerStore';
import { api, getImageUrl, getAudioUrl, getOfflineAudioUrl } from '../services/api';
import { AnimatePresence, motion } from 'framer-motion';
import { DownloadQualityModal } from './DownloadQualityModal';
import { Song } from '../types';
import { useNavigate } from 'react-router-dom';

export const Player: React.FC = () => {
  const { 
    currentSong, 
    isPlaying, 
    isBuffering,
    isFullScreen,
    setFullScreen,
    togglePlay, 
    setIsPlaying, 
    setIsBuffering,
    nextSong, 
    prevSong,
    likedSongs,
    toggleLike,
    isShuffling,
    streamingQuality,
    isOfflineMode,
    downloadedSongIds,
    addToQueue
  } = usePlayerStore();

  const navigate = useNavigate();
  const audioRef = useRef<HTMLAudioElement>(null);

  const [progress, setProgress] = useState(0);
  const [duration, setDuration] = useState(0);
  const [dominantColor, setDominantColor] = useState<string>('#121212');
  const [isDragging, setIsDragging] = useState(false);

  const [downloadSong, setDownloadSong] = useState<Song | null>(null);
  const [isMoreMenuOpen, setIsMoreMenuOpen] = useState(false);

  // New States for enhanced features
  const [sleepTimerId, setSleepTimerId] = useState<number | null>(null);
  const [toastMessage, setToastMessage] = useState<string | null>(null);

  const [touchStart, setTouchStart] = useState<{x: number, y: number} | null>(null);

  const isLiked = currentSong ? likedSongs.some(s => s.id === currentSong.id) : false;
  const isDownloaded = currentSong ? downloadedSongIds.includes(currentSong.id) : false;

  // Extract color from image
  useEffect(() => {
    if (!currentSong) return;
    const imgUrl = getImageUrl(currentSong.image);
    const img = new Image();
    img.crossOrigin = "Anonymous";
    img.src = imgUrl;

    img.onload = () => {
      try {
        const canvas = document.createElement('canvas');
        const ctx = canvas.getContext('2d');
        if (!ctx) return;
        canvas.width = 1; 
        canvas.height = 1;
        ctx.drawImage(img, 0, 0, 1, 1);
        const [r, g, b] = ctx.getImageData(0, 0, 1, 1).data;
        setDominantColor(`rgb(${Math.max(20, r - 30)},${Math.max(20, g - 30)},${Math.max(20, b - 30)})`);
      } catch (e) {
        setDominantColor('#181818'); 
      }
    };
    img.onerror = () => setDominantColor('#181818');
  }, [currentSong?.id]);

  // MEDIA SESSION API INTEGRATION (Notification Poster)
  useEffect(() => {
    if (!currentSong || !('mediaSession' in navigator)) return;

    const artistName = currentSong.artists?.primary?.[0]?.name || "Unknown";
    // Get the high-quality image for the notification poster
    const hqImage = getImageUrl(currentSong.image);

    navigator.mediaSession.metadata = new MediaMetadata({
      title: currentSong.name,
      artist: artistName,
      album: currentSong.album?.name || "Single",
      artwork: [
          { src: hqImage, sizes: '96x96', type: 'image/jpeg' },
          { src: hqImage, sizes: '128x128', type: 'image/jpeg' },
          { src: hqImage, sizes: '192x192', type: 'image/jpeg' },
          { src: hqImage, sizes: '256x256', type: 'image/jpeg' },
          { src: hqImage, sizes: '384x384', type: 'image/jpeg' },
          { src: hqImage, sizes: '512x512', type: 'image/jpeg' },
      ]
    });

    navigator.mediaSession.setActionHandler('play', () => setIsPlaying(true));
    navigator.mediaSession.setActionHandler('pause', () => setIsPlaying(false));
    navigator.mediaSession.setActionHandler('previoustrack', prevSong);
    navigator.mediaSession.setActionHandler('nexttrack', nextSong);
    navigator.mediaSession.setActionHandler('seekto', (details) => {
        if (audioRef.current && details.seekTime !== undefined) {
            audioRef.current.currentTime = details.seekTime;
            setProgress(details.seekTime);
        }
    });
  }, [currentSong, setIsPlaying, prevSong, nextSong]);

  // Sync Playback State with Media Session
  useEffect(() => {
      if ('mediaSession' in navigator) {
          navigator.mediaSession.playbackState = isPlaying ? "playing" : "paused";
      }
  }, [isPlaying]);

  // Audio Source Logic
  useEffect(() => {
    if (!currentSong || !audioRef.current) return;

    const setAudioSource = async () => {
        let url = '';
        if (isOfflineMode || downloadedSongIds.includes(currentSong.id)) {
            const blobUrl = await getOfflineAudioUrl(currentSong.id);
            if (blobUrl) url = blobUrl;
            else if (isOfflineMode) { setIsPlaying(false); return; }
        }
        if (!url && !isOfflineMode) {
             url = getAudioUrl(currentSong.downloadUrl, streamingQuality);
        }
        if (url && audioRef.current && audioRef.current.src !== url) {
            const wasPlaying = isPlaying;
            audioRef.current.src = url;
            audioRef.current.load();
            if (wasPlaying) {
                 audioRef.current.play().catch(() => setIsPlaying(false));
            }
        }
    };
    setAudioSource();
  }, [currentSong?.id, streamingQuality, isOfflineMode]);

  useEffect(() => {
    const audio = audioRef.current;
    if (!audio) return;
    if (isPlaying && audio.paused) audio.play().catch(e => console.warn("Play interrupted", e));
    else if (!isPlaying && !audio.paused) audio.pause();
  }, [isPlaying]);

  const handleTimeUpdate = () => {
    if (audioRef.current && !isDragging) {
      const currentTime = audioRef.current.currentTime;
      const duration = audioRef.current.duration || 0;

      setProgress(currentTime);
      setDuration(duration);

      if ('mediaSession' in navigator && duration > 0 && !isNaN(duration)) {
          try {
            navigator.mediaSession.setPositionState({
                duration: duration,
                playbackRate: audioRef.current.playbackRate,
                position: currentTime
            });
          } catch (e) {}
      }
    }
  };

  const handleSeek = (e: React.ChangeEvent<HTMLInputElement>) => {
    const time = parseFloat(e.target.value);
    setProgress(time);
    if (audioRef.current) audioRef.current.currentTime = time;
  };

  const formatTime = (seconds: number) => {
    if (!seconds || isNaN(seconds)) return "-:--";
    const mins = Math.floor(seconds / 60);
    const secs = Math.floor(seconds % 60);
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  // Helper to show temporary messages
  const showToast = (msg: string) => {
      setToastMessage(msg);
      setTimeout(() => setToastMessage(null), 2500);
  };

  // --- ACTIONS FOR MORE MENU ---
  const handleAddToQueue = () => {
      if(currentSong) {
          addToQueue(currentSong);
          showToast("Added to queue");
          setIsMoreMenuOpen(false);
      }
  };

  const handleShare = async () => {
      if(!currentSong) return;
      const shareData = {
          title: currentSong.name,
          text: `Listen to ${currentSong.name} by ${currentSong.artists.primary[0].name}`,
          url: window.location.href
      };

      if (navigator.share) {
          try {
              await navigator.share(shareData);
          } catch(e) { console.log(e); }
      } else {
          navigator.clipboard.writeText(shareData.url);
          showToast("Link copied to clipboard");
      }
      setIsMoreMenuOpen(false);
  };

  const handleSleepTimer = () => {
      if (sleepTimerId) {
          clearTimeout(sleepTimerId);
          setSleepTimerId(null);
          showToast("Sleep timer turned off");
      } else {
          // Set for 30 mins
          const id = window.setTimeout(() => {
              setIsPlaying(false);
              setSleepTimerId(null);
          }, 30 * 60 * 1000); 
          setSleepTimerId(id);
          showToast("Sleep timer set for 30 minutes");
      }
      setIsMoreMenuOpen(false);
  };

  const handleGoToRadio = async () => {
      if(!currentSong) return;
      setIsMoreMenuOpen(false);
      showToast(`Starting radio for ${currentSong.name}`);

      try {
         // Fetch recommendations (mocked by searching artist)
         const query = currentSong.artists.primary[0]?.name || currentSong.name;
         const songs = await api.searchSongs(query);
         const newSongs = songs.filter(s => s.id !== currentSong.id);

         if (newSongs.length > 0) {
             // Add first 10 to queue
             newSongs.slice(0, 10).forEach(s => addToQueue(s));
             showToast(`Added ${Math.min(newSongs.length, 10)} songs to queue`);
         } else {
             showToast("No similar songs found");
         }
      } catch(e) {
          console.error("Radio failed", e);
          showToast("Failed to start radio");
      }
  };

  const handleTouchStart = (e: React.TouchEvent) => {
    setTouchStart({ x: e.targetTouches[0].clientX, y: e.targetTouches[0].clientY });
  };

  const handleTouchEnd = (e: React.TouchEvent) => {
    if (!touchStart) return;
    const touchEndX = e.changedTouches[0].clientX;
    const touchEndY = e.changedTouches[0].clientY;
    const diffX = touchStart.x - touchEndX;
    const diffY = touchStart.y - touchEndY;

    if (Math.abs(diffX) > 50 && Math.abs(diffX) > Math.abs(diffY)) {
      if (diffX > 0) nextSong();
      else prevSong();
    }
    if (diffY < -80 && Math.abs(diffY) > Math.abs(diffX) && !isMoreMenuOpen) {
        setFullScreen(false);
    }
    setTouchStart(null);
  };

  if (!currentSong) return null;

  const imageUrl = getImageUrl(currentSong.image);
  const primaryArtistName = currentSong.artists?.primary?.[0]?.name || "Unknown";

  return (
    <>
        <audio 
            ref={audioRef}
            preload="auto"
            onTimeUpdate={handleTimeUpdate}
            onEnded={nextSong}
            onWaiting={() => setIsBuffering(true)}
            onPlaying={() => setIsBuffering(false)}
            onCanPlay={() => setIsBuffering(false)}
            onPause={() => {
                if (isPlaying && !isBuffering && audioRef.current?.paused) setIsPlaying(false);
            }}
            onPlay={() => !isPlaying && setIsPlaying(true)}
        />

        <AnimatePresence mode="wait">
            {isFullScreen ? (
                <motion.div 
                    key="full-player"
                    initial={{ y: "100%" }}
                    animate={{ y: 0 }}
                    exit={{ y: "100%" }}
                    transition={{ type: "spring", damping: 30, stiffness: 300, mass: 0.8 }}
                    className="fixed inset-0 z-[200] flex flex-col bg-[#121212] isolate overflow-hidden"
                    onClick={(e) => e.stopPropagation()}
                    onTouchStart={handleTouchStart}
                    onTouchEnd={handleTouchEnd}
                >
                    {/* Background */}
                    <div 
                        className="absolute inset-0 z-[-1]"
                        style={{ 
                            background: `linear-gradient(to bottom, ${dominantColor}, #121212)`,
                        }}
                    />

                    {/* FULL PLAYER CONTENT */}
                    <div className="relative z-10 flex flex-col h-full px-6 pt-safe-top pb-safe-bottom">

                        {/* Header */}
                        <div className="flex items-center justify-between h-16 shrink-0 mt-2">
                            <button onClick={() => setFullScreen(false)} className="p-2 -ml-2 rounded-full hover:bg-white/10 shrink-0">
                                <ChevronDown size={28} className="text-white" />
                            </button>
                            <span className="text-[11px] font-bold tracking-[0.15em] uppercase text-white/70">
                                Now Playing
                            </span>
                            <button onClick={() => setIsMoreMenuOpen(true)} className="p-2 -mr-2 rounded-full hover:bg-white/10 shrink-0">
                                <MoreHorizontal size={24} className="text-white" />
                            </button>
                        </div>

                        {/* Main Artwork Area */}
                        <div className="flex-1 flex flex-col justify-center min-h-0 relative my-4">
                            <div className="relative w-full aspect-square max-w-[340px] mx-auto shadow-2xl rounded-xl overflow-hidden">
                                <img 
                                    src={imageUrl} 
                                    alt="Cover"
                                    className="w-full h-full object-cover"
                                />
                            </div>
                        </div>

                        {/* Info & Controls */}
                        <div className="flex flex-col gap-6 mb-10">
                            <div className="flex items-center justify-between">
                                <div className="flex flex-col overflow-hidden mr-4 min-w-0">
                                    <h2 className="text-2xl font-bold text-white truncate">
                                        {currentSong.name}
                                    </h2>
                                    <p className="text-lg text-white/70 truncate">
                                        {primaryArtistName}
                                    </p>
                                </div>
                                <button onClick={() => toggleLike(currentSong)} className="shrink-0">
                                    {isLiked ? <CheckCircle2 size={28} className="text-[#1DB954] fill-black" /> : <PlusCircle size={28} className="text-white/70" />}
                                </button>
                            </div>

                            {/* Scrubber */}
                            <div className="flex flex-col gap-2">
                                <div className="relative h-1 w-full bg-white/20 rounded-full group hover:h-1.5 transition-all">
                                     <div className="absolute left-0 top-0 bottom-0 bg-white rounded-full" style={{ width: `${(progress / (duration || 1)) * 100}%` }}>
                                        <div className="absolute right-0 top-1/2 -translate-y-1/2 w-3 h-3 bg-white rounded-full opacity-0 group-hover:opacity-100"></div>
                                     </div>
                                     <input 
                                        type="range" min="0" max={duration || 100} value={progress}
                                        onChange={handleSeek}
                                        onMouseDown={() => setIsDragging(true)}
                                        onTouchStart={() => setIsDragging(true)}
                                        onMouseUp={() => setIsDragging(false)}
                                        onTouchEnd={() => setIsDragging(false)}
                                        className="absolute inset-0 opacity-0 cursor-pointer"
                                    />
                                </div>
                                <div className="flex justify-between text-[11px] text-white/50 font-mono font-medium">
                                    <span>{formatTime(progress)}</span>
                                    <span>{formatTime(duration)}</span>
                                </div>
                            </div>

                            {/* Controls */}
                            <div className="flex items-center justify-between px-2">
                                <button className={`shrink-0 ${isShuffling ? 'text-[#1DB954]' : 'text-white/40'}`}><Shuffle size={20} /></button>
                                <button onClick={prevSong} className="shrink-0"><SkipBack size={32} className="text-white" fill="white" /></button>
                                <button 
                                    onClick={togglePlay}
                                    className="w-16 h-16 bg-white rounded-full flex items-center justify-center hover:scale-105 active:scale-95 transition-transform shrink-0"
                                >
                                    {isBuffering ? <Loader2 size={32} className="animate-spin text-black" /> : isPlaying ? <Pause size={32} fill="black" className="text-black" /> : <Play size={32} fill="black" className="ml-1 text-black" />}
                                </button>
                                <button onClick={nextSong} className="shrink-0"><SkipForward size={32} className="text-white" fill="white" /></button>
                                <button className="text-white/40 shrink-0"><Repeat size={20} /></button>
                            </div>

                            {/* Bottom Row */}
                            <div className="flex items-center justify-between px-4">
                                <button onClick={() => setDownloadSong(currentSong)} className={`shrink-0 ${isDownloaded ? 'text-[#1DB954]' : 'text-white/50'}`}>
                                    <Download size={22} />
                                </button>
                                <button className="text-white/50 shrink-0"><ListMusic size={22} /></button>
                            </div>
                        </div>
                    </div>

                    {/* Toast Notification */}
                    <AnimatePresence>
                        {toastMessage && (
                            <motion.div 
                                initial={{ opacity: 0, y: 20 }}
                                animate={{ opacity: 1, y: 0 }}
                                exit={{ opacity: 0, y: 20 }}
                                className="absolute bottom-32 left-1/2 -translate-x-1/2 z-[300] bg-white text-black px-6 py-3 rounded-full font-bold shadow-xl text-sm whitespace-nowrap"
                            >
                                {toastMessage}
                            </motion.div>
                        )}
                    </AnimatePresence>

                    {/* More Menu (Enhanced) */}
                    <AnimatePresence>
                        {isMoreMenuOpen && (
                            <motion.div 
                                initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
                                className="absolute inset-0 z-[250] bg-black/60 backdrop-blur-sm flex flex-col justify-end"
                                onClick={() => setIsMoreMenuOpen(false)}
                            >
                                <motion.div 
                                    initial={{ y: "100%" }} animate={{ y: 0 }} exit={{ y: "100%" }}
                                    transition={{ type: "tween", ease: "circOut", duration: 0.3 }}
                                    drag="y"
                                    dragConstraints={{ top: 0 }}
                                    dragElastic={{ top: 0, bottom: 0.2 }}
                                    onDragEnd={(_, info) => {
                                        if (info.offset.y > 100 || info.velocity.y > 100) {
                                            setIsMoreMenuOpen(false);
                                        }
                                    }}
                                    className="bg-[#242424] rounded-t-2xl flex flex-col max-h-[80vh] overflow-y-auto pb-6"
                                    onClick={e => e.stopPropagation()}
                                >
                                    {/* Drag Handle */}
                                    <div className="w-full flex justify-center pt-4 pb-2">
                                        <div className="w-10 h-1 bg-white/20 rounded-full"></div>
                                    </div>

                                    {/* Song Context Info */}
                                    <div className="flex items-center gap-3 px-6 pb-6 border-b border-white/5">
                                        <img src={getImageUrl(currentSong.image)} className="w-12 h-12 rounded-md object-cover shadow-lg" alt="" />
                                        <div>
                                            <div className="font-bold text-white text-[15px]">{currentSong.name}</div>
                                            <div className="text-sm text-white/60">{primaryArtistName}</div>
                                        </div>
                                    </div>

                                    {/* Menu Actions List */}
                                    <div className="flex flex-col py-2">

                                        <button onClick={() => { toggleLike(currentSong); setIsMoreMenuOpen(false); showToast(isLiked ? "Removed from Liked Songs" : "Added to Liked Songs"); }} className="flex items-center gap-4 px-6 py-3.5 hover:bg-white/5 active:bg-black/20 transition-colors">
                                            <Heart size={24} className={isLiked ? "text-[#1DB954] fill-[#1DB954]" : "text-white/80"} />
                                            <span className="text-white font-medium">{isLiked ? 'Liked' : 'Like'}</span>
                                        </button>

                                        <button onClick={handleAddToQueue} className="flex items-center gap-4 px-6 py-3.5 hover:bg-white/5 active:bg-black/20 transition-colors">
                                            <ListPlus size={24} className="text-white/80" />
                                            <span className="text-white font-medium">Add to queue</span>
                                        </button>

                                        <button onClick={handleShare} className="flex items-center gap-4 px-6 py-3.5 hover:bg-white/5 active:bg-black/20 transition-colors">
                                            <Share2 size={24} className="text-white/80" />
                                            <span className="text-white font-medium">Share</span>
                                        </button>

                                        <button onClick={() => { setIsMoreMenuOpen(false); navigate(`/artist/${currentSong.artists.primary[0].id}`, { state: { artist: currentSong.artists.primary[0] } }); }} className="flex items-center gap-4 px-6 py-3.5 hover:bg-white/5 active:bg-black/20 transition-colors">
                                            <User size={24} className="text-white/80" />
                                            <span className="text-white font-medium">View Artist</span>
                                        </button>

                                        <button onClick={() => { setIsMoreMenuOpen(false); navigate(`/album/${currentSong.album.id}`); }} className="flex items-center gap-4 px-6 py-3.5 hover:bg-white/5 active:bg-black/20 transition-colors">
                                            <Disc size={24} className="text-white/80" />
                                            <span className="text-white font-medium">View Album</span>
                                        </button>

                                        <button onClick={handleSleepTimer} className="flex items-center gap-4 px-6 py-3.5 hover:bg-white/5 active:bg-black/20 transition-colors">
                                            <Moon size={24} className={sleepTimerId ? "text-[#1DB954]" : "text-white/80"} />
                                            <span className="text-white font-medium">{sleepTimerId ? 'Stop Sleep Timer' : 'Sleep Timer (30 mins)'}</span>
                                        </button>

                                        <button onClick={handleGoToRadio} className="flex items-center gap-4 px-6 py-3.5 hover:bg-white/5 active:bg-black/20 transition-colors">
                                            <Radio size={24} className="text-white/80" />
                                            <span className="text-white font-medium">Go to Song Radio</span>
                                        </button>

                                        <button onClick={() => showToast("Credits: Written by " + primaryArtistName)} className="flex items-center gap-4 px-6 py-3.5 hover:bg-white/5 active:bg-black/20 transition-colors">
                                            <Mic2 size={24} className="text-white/80" />
                                            <span className="text-white font-medium">Show credits</span>
                                        </button>

                                    </div>

                                </motion.div>
                            </motion.div>
                        )}
                    </AnimatePresence>
                </motion.div>
            ) : (
                <motion.div 
                    key="mini-player"
                    initial={{ y: 50, opacity: 0 }}
                    animate={{ y: 0, opacity: 1 }}
                    exit={{ y: 50, opacity: 0 }}
                    transition={{ type: "spring", stiffness: 400, damping: 30 }}
                    className="fixed bottom-[68px] md:bottom-4 left-2 right-2 md:left-1/2 md:-translate-x-1/2 md:w-[450px] h-[56px] z-[150] cursor-pointer isolate"
                    onClick={() => setFullScreen(true)}
                >
                    {/* Background */}
                    <div 
                        className="absolute inset-0 z-[-1] rounded-lg shadow-xl overflow-hidden"
                        style={{ backgroundColor: dominantColor }}
                    >
                         <div className="absolute inset-0 bg-black/20" />
                    </div>

                    <div className="flex items-center h-full px-2 gap-3">
                        {/* Image */}
                        <div className="h-10 w-10 shrink-0 rounded-[4px] overflow-hidden shadow-sm">
                            <img src={imageUrl} alt="" className="w-full h-full object-cover" />
                        </div>

                        {/* Text Info */}
                        <div className="flex-1 flex flex-col justify-center min-w-0 pr-2">
                            <span className="text-white font-bold text-xs truncate">
                                {currentSong.name}
                            </span>
                            <span className="text-white/70 text-[10px] truncate">
                                {primaryArtistName}
                            </span>
                        </div>

                        {/* Controls */}
                        <div className="flex items-center gap-1.5 pr-1 shrink-0">
                            {/* Like Button */}
                            <button onClick={(e) => { e.stopPropagation(); toggleLike(currentSong); }} className="shrink-0 p-1.5">
                                <Heart size={20} fill={isLiked ? "#1DB954" : "none"} className={isLiked ? "text-[#1DB954]" : "text-white"} />
                            </button>

                            {/* Previous Button (Hidden on very small screens if needed, but fitting here) */}
                            <button onClick={(e) => { e.stopPropagation(); prevSong(); }} className="shrink-0 p-1.5 text-white/90 hover:text-white">
                                <SkipBack size={22} fill="white" />
                            </button>

                            {/* Play/Pause Button */}
                            <button onClick={(e) => { e.stopPropagation(); togglePlay(); }} className="shrink-0 p-1.5">
                                {isBuffering ? (
                                    <Loader2 size={24} className="animate-spin text-white" />
                                ) : isPlaying ? (
                                    <Pause size={24} fill="white" className="text-white" />
                                ) : (
                                    <Play size={24} fill="white" className="text-white" />
                                )}
                            </button>

                            {/* Next Button */}
                            <button onClick={(e) => { e.stopPropagation(); nextSong(); }} className="shrink-0 p-1.5 text-white/90 hover:text-white">
                                <SkipForward size={22} fill="white" />
                            </button>
                        </div>
                    </div>

                    {/* Progress Bar (Mini only) */}
                    <div className="absolute bottom-0 left-1 right-1 h-[2px] bg-white/20 rounded-full overflow-hidden">
                        <div className="h-full bg-white rounded-full" style={{ width: `${(progress / (duration || 1)) * 100}%` }}></div>
                    </div>
                </motion.div>
            )}
        </AnimatePresence>

        {downloadSong && (
            <DownloadQualityModal song={downloadSong} onClose={() => setDownloadSong(null)} />
        )}
    </>
  );
};

import React, { useRef, useEffect, useState } from 'react';
import { Play, Pause, SkipBack, SkipForward, ChevronDown, MoreHorizontal, Download, ListMusic, Heart, Loader2, Shuffle, Repeat, PlusCircle, CheckCircle2, Disc, User, Share2, ListPlus, Radio, Mic2, Moon, Timer, X, Copy } from 'lucide-react';
import { usePlayerStore } from '../store/playerStore';
import { api, getImageUrl, getAudioUrl, getOfflineAudioUrl } from '../services/api';
import { AnimatePresence, motion } from 'framer-motion';
import { DownloadQualityModal } from './DownloadQualityModal';
import { Song } from '../types';
import { useNavigate } from 'react-router-dom';

export const Player: React.FC = () => {
  const { 
    currentSong, 
    isPlaying, 
    isBuffering,
    isFullScreen,
    setFullScreen,
    togglePlay, 
    setIsPlaying, 
    setIsBuffering,
    nextSong, 
    prevSong,
    likedSongs,
    toggleLike,
    isShuffling,
    streamingQuality,
    isOfflineMode,
    downloadedSongIds,
    addToQueue
  } = usePlayerStore();

  const navigate = useNavigate();
  const audioRef = useRef<HTMLAudioElement>(null);

  const [progress, setProgress] = useState(0);
  const [duration, setDuration] = useState(0);
  const [dominantColor, setDominantColor] = useState<string>('#121212');
  const [isDragging, setIsDragging] = useState(false);

  const [downloadSong, setDownloadSong] = useState<Song | null>(null);
  const [isMoreMenuOpen, setIsMoreMenuOpen] = useState(false);

  // New States for enhanced features
  const [sleepTimerId, setSleepTimerId] = useState<number | null>(null);
  const [toastMessage, setToastMessage] = useState<string | null>(null);

  const [touchStart, setTouchStart] = useState<{x: number, y: number} | null>(null);

  const isLiked = currentSong ? likedSongs.some(s => s.id === currentSong.id) : false;
  const isDownloaded = currentSong ? downloadedSongIds.includes(currentSong.id) : false;

  // Extract color from image
  useEffect(() => {
    if (!currentSong) return;
    const imgUrl = getImageUrl(currentSong.image);
    const img = new Image();
    img.crossOrigin = "Anonymous";
    img.src = imgUrl;

    img.onload = () => {
      try {
        const canvas = document.createElement('canvas');
        const ctx = canvas.getContext('2d');
        if (!ctx) return;
        canvas.width = 1; 
        canvas.height = 1;
        ctx.drawImage(img, 0, 0, 1, 1);
        const [r, g, b] = ctx.getImageData(0, 0, 1, 1).data;
        setDominantColor(`rgb(${Math.max(20, r - 30)},${Math.max(20, g - 30)},${Math.max(20, b - 30)})`);
      } catch (e) {
        setDominantColor('#181818'); 
      }
    };
    img.onerror = () => setDominantColor('#181818');
  }, [currentSong?.id]);

  // MEDIA SESSION API INTEGRATION (Notification Poster)
  useEffect(() => {
    if (!currentSong || !('mediaSession' in navigator)) return;

    const artistName = currentSong.artists?.primary?.[0]?.name || "Unknown";
    // Get the high-quality image for the notification poster
    const hqImage = getImageUrl(currentSong.image);

    navigator.mediaSession.metadata = new MediaMetadata({
      title: currentSong.name,
      artist: artistName,
      album: currentSong.album?.name || "Single",
      artwork: [
          { src: hqImage, sizes: '96x96', type: 'image/jpeg' },
          { src: hqImage, sizes: '128x128', type: 'image/jpeg' },
          { src: hqImage, sizes: '192x192', type: 'image/jpeg' },
          { src: hqImage, sizes: '256x256', type: 'image/jpeg' },
          { src: hqImage, sizes: '384x384', type: 'image/jpeg' },
          { src: hqImage, sizes: '512x512', type: 'image/jpeg' },
      ]
    });

    navigator.mediaSession.setActionHandler('play', () => setIsPlaying(true));
    navigator.mediaSession.setActionHandler('pause', () => setIsPlaying(false));
    navigator.mediaSession.setActionHandler('previoustrack', prevSong);
    navigator.mediaSession.setActionHandler('nexttrack', nextSong);
    navigator.mediaSession.setActionHandler('seekto', (details) => {
        if (audioRef.current && details.seekTime !== undefined) {
            audioRef.current.currentTime = details.seekTime;
            setProgress(details.seekTime);
        }
    });
  }, [currentSong, setIsPlaying, prevSong, nextSong]);

  // Sync Playback State with Media Session
  useEffect(() => {
      if ('mediaSession' in navigator) {
          navigator.mediaSession.playbackState = isPlaying ? "playing" : "paused";
      }
  }, [isPlaying]);

  // Audio Source Logic
  useEffect(() => {
    if (!currentSong || !audioRef.current) return;

    const setAudioSource = async () => {
        let url = '';
        if (isOfflineMode || downloadedSongIds.includes(currentSong.id)) {
            const blobUrl = await getOfflineAudioUrl(currentSong.id);
            if (blobUrl) url = blobUrl;
            else if (isOfflineMode) { setIsPlaying(false); return; }
        }
        if (!url && !isOfflineMode) {
             url = getAudioUrl(currentSong.downloadUrl, streamingQuality);
        }
        if (url && audioRef.current && audioRef.current.src !== url) {
            const wasPlaying = isPlaying;
            audioRef.current.src = url;
            audioRef.current.load();
            if (wasPlaying) {
                 audioRef.current.play().catch(() => setIsPlaying(false));
            }
        }
    };
    setAudioSource();
  }, [currentSong?.id, streamingQuality, isOfflineMode]);

  useEffect(() => {
    const audio = audioRef.current;
    if (!audio) return;
    if (isPlaying && audio.paused) audio.play().catch(e => console.warn("Play interrupted", e));
    else if (!isPlaying && !audio.paused) audio.pause();
  }, [isPlaying]);

  const handleTimeUpdate = () => {
    if (audioRef.current && !isDragging) {
      const currentTime = audioRef.current.currentTime;
      const duration = audioRef.current.duration || 0;

      setProgress(currentTime);
      setDuration(duration);

      if ('mediaSession' in navigator && duration > 0 && !isNaN(duration)) {
          try {
            navigator.mediaSession.setPositionState({
                duration: duration,
                playbackRate: audioRef.current.playbackRate,
                position: currentTime
            });
          } catch (e) {}
      }
    }
  };

  const handleSeek = (e: React.ChangeEvent<HTMLInputElement>) => {
    const time = parseFloat(e.target.value);
    setProgress(time);
    if (audioRef.current) audioRef.current.currentTime = time;
  };

  const formatTime = (seconds: number) => {
    if (!seconds || isNaN(seconds)) return "-:--";
    const mins = Math.floor(seconds / 60);
    const secs = Math.floor(seconds % 60);
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  // Helper to show temporary messages
  const showToast = (msg: string) => {
      setToastMessage(msg);
      setTimeout(() => setToastMessage(null), 2500);
  };

  // --- ACTIONS FOR MORE MENU ---
  const handleAddToQueue = () => {
      if(currentSong) {
          addToQueue(currentSong);
          showToast("Added to queue");
          setIsMoreMenuOpen(false);
      }
  };

  const handleShare = async () => {
      if(!currentSong) return;
      const shareData = {
          title: currentSong.name,
          text: `Listen to ${currentSong.name} by ${currentSong.artists.primary[0].name}`,
          url: window.location.href
      };

      if (navigator.share) {
          try {
              await navigator.share(shareData);
          } catch(e) { console.log(e); }
      } else {
          navigator.clipboard.writeText(shareData.url);
          showToast("Link copied to clipboard");
      }
      setIsMoreMenuOpen(false);
  };

  const handleSleepTimer = () => {
      if (sleepTimerId) {
          clearTimeout(sleepTimerId);
          setSleepTimerId(null);
          showToast("Sleep timer turned off");
      } else {
          // Set for 30 mins
          const id = window.setTimeout(() => {
              setIsPlaying(false);
              setSleepTimerId(null);
          }, 30 * 60 * 1000); 
          setSleepTimerId(id);
          showToast("Sleep timer set for 30 minutes");
      }
      setIsMoreMenuOpen(false);
  };

  const handleGoToRadio = async () => {
      if(!currentSong) return;
      setIsMoreMenuOpen(false);
      showToast(`Starting radio for ${currentSong.name}`);

      try {
         // Fetch recommendations (mocked by searching artist)
         const query = currentSong.artists.primary[0]?.name || currentSong.name;
         const songs = await api.searchSongs(query);
         const newSongs = songs.filter(s => s.id !== currentSong.id);

         if (newSongs.length > 0) {
             // Add first 10 to queue
             newSongs.slice(0, 10).forEach(s => addToQueue(s));
             showToast(`Added ${Math.min(newSongs.length, 10)} songs to queue`);
         } else {
             showToast("No similar songs found");
         }
      } catch(e) {
          console.error("Radio failed", e);
          showToast("Failed to start radio");
      }
  };

  const handleTouchStart = (e: React.TouchEvent) => {
    setTouchStart({ x: e.targetTouches[0].clientX, y: e.targetTouches[0].clientY });
  };

  const handleTouchEnd = (e: React.TouchEvent) => {
    if (!touchStart) return;
    const touchEndX = e.changedTouches[0].clientX;
    const touchEndY = e.changedTouches[0].clientY;
    const diffX = touchStart.x - touchEndX;
    const diffY = touchStart.y - touchEndY;

    if (Math.abs(diffX) > 50 && Math.abs(diffX) > Math.abs(diffY)) {
      if (diffX > 0) nextSong();
      else prevSong();
    }
    if (diffY < -80 && Math.abs(diffY) > Math.abs(diffX) && !isMoreMenuOpen) {
        setFullScreen(false);
    }
    setTouchStart(null);
  };

  if (!currentSong) return null;

  const imageUrl = getImageUrl(currentSong.image);
  const primaryArtistName = currentSong.artists?.primary?.[0]?.name || "Unknown";

  return (
    <>
        <audio 
            ref={audioRef}
            preload="auto"
            onTimeUpdate={handleTimeUpdate}
            onEnded={nextSong}
            onWaiting={() => setIsBuffering(true)}
            onPlaying={() => setIsBuffering(false)}
            onCanPlay={() => setIsBuffering(false)}
            onPause={() => {
                if (isPlaying && !isBuffering && audioRef.current?.paused) setIsPlaying(false);
            }}
            onPlay={() => !isPlaying && setIsPlaying(true)}
        />

        <AnimatePresence mode="wait">
            {isFullScreen ? (
                <motion.div 
                    key="full-player"
                    initial={{ y: "100%" }}
                    animate={{ y: 0 }}
                    exit={{ y: "100%" }}
                    transition={{ type: "spring", damping: 30, stiffness: 300, mass: 0.8 }}
                    className="fixed inset-0 z-[200] flex flex-col bg-[#121212] isolate overflow-hidden"
                    onClick={(e) => e.stopPropagation()}
                    onTouchStart={handleTouchStart}
                    onTouchEnd={handleTouchEnd}
                >
                    {/* Background */}
                    <div 
                        className="absolute inset-0 z-[-1]"
                        style={{ 
                            background: `linear-gradient(to bottom, ${dominantColor}, #121212)`,
                        }}
                    />

                    {/* FULL PLAYER CONTENT */}
                    <div className="relative z-10 flex flex-col h-full px-6 pt-safe-top pb-safe-bottom">

                        {/* Header */}
                        <div className="flex items-center justify-between h-16 shrink-0 mt-2">
                            <button onClick={() => setFullScreen(false)} className="p-2 -ml-2 rounded-full hover:bg-white/10 shrink-0">
                                <ChevronDown size={28} className="text-white" />
                            </button>
                            <span className="text-[11px] font-bold tracking-[0.15em] uppercase text-white/70">
                                Now Playing
                            </span>
                            <button onClick={() => setIsMoreMenuOpen(true)} className="p-2 -mr-2 rounded-full hover:bg-white/10 shrink-0">
                                <MoreHorizontal size={24} className="text-white" />
                            </button>
                        </div>

                        {/* Main Artwork Area */}
                        <div className="flex-1 flex flex-col justify-center min-h-0 relative my-4">
                            <div className="relative w-full aspect-square max-w-[340px] mx-auto shadow-2xl rounded-xl overflow-hidden">
                                <img 
                                    src={imageUrl} 
                                    alt="Cover"
                                    className="w-full h-full object-cover"
                                />
                            </div>
                        </div>

                        {/* Info & Controls */}
                        <div className="flex flex-col gap-6 mb-10">
                            <div className="flex items-center justify-between">
                                <div className="flex flex-col overflow-hidden mr-4 min-w-0">
                                    <h2 className="text-2xl font-bold text-white truncate">
                                        {currentSong.name}
                                    </h2>
                                    <p className="text-lg text-white/70 truncate">
                                        {primaryArtistName}
                                    </p>
                                </div>
                                <button onClick={() => toggleLike(currentSong)} className="shrink-0">
                                    {isLiked ? <CheckCircle2 size={28} className="text-[#1DB954] fill-black" /> : <PlusCircle size={28} className="text-white/70" />}
                                </button>
                            </div>

                            {/* Scrubber */}
                            <div className="flex flex-col gap-2">
                                <div className="relative h-1 w-full bg-white/20 rounded-full group hover:h-1.5 transition-all">
                                     <div className="absolute left-0 top-0 bottom-0 bg-white rounded-full" style={{ width: `${(progress / (duration || 1)) * 100}%` }}>
                                        <div className="absolute right-0 top-1/2 -translate-y-1/2 w-3 h-3 bg-white rounded-full opacity-0 group-hover:opacity-100"></div>
                                     </div>
                                     <input 
                                        type="range" min="0" max={duration || 100} value={progress}
                                        onChange={handleSeek}
                                        onMouseDown={() => setIsDragging(true)}
                                        onTouchStart={() => setIsDragging(true)}
                                        onMouseUp={() => setIsDragging(false)}
                                        onTouchEnd={() => setIsDragging(false)}
                                        className="absolute inset-0 opacity-0 cursor-pointer"
                                    />
                                </div>
                                <div className="flex justify-between text-[11px] text-white/50 font-mono font-medium">
                                    <span>{formatTime(progress)}</span>
                                    <span>{formatTime(duration)}</span>
                                </div>
                            </div>

                            {/* Controls */}
                            <div className="flex items-center justify-between px-2">
                                <button className={`shrink-0 ${isShuffling ? 'text-[#1DB954]' : 'text-white/40'}`}><Shuffle size={20} /></button>
                                <button onClick={prevSong} className="shrink-0"><SkipBack size={32} className="text-white" fill="white" /></button>
                                <button 
                                    onClick={togglePlay}
                                    className="w-16 h-16 bg-white rounded-full flex items-center justify-center hover:scale-105 active:scale-95 transition-transform shrink-0"
                                >
                                    {isBuffering ? <Loader2 size={32} className="animate-spin text-black" /> : isPlaying ? <Pause size={32} fill="black" className="text-black" /> : <Play size={32} fill="black" className="ml-1 text-black" />}
                                </button>
                                <button onClick={nextSong} className="shrink-0"><SkipForward size={32} className="text-white" fill="white" /></button>
                                <button className="text-white/40 shrink-0"><Repeat size={20} /></button>
                            </div>

                            {/* Bottom Row */}
                            <div className="flex items-center justify-between px-4">
                                <button onClick={() => setDownloadSong(currentSong)} className={`shrink-0 ${isDownloaded ? 'text-[#1DB954]' : 'text-white/50'}`}>
                                    <Download size={22} />
                                </button>
                                <button className="text-white/50 shrink-0"><ListMusic size={22} /></button>
                            </div>
                        </div>
                    </div>

                    {/* Toast Notification */}
                    <AnimatePresence>
                        {toastMessage && (
                            <motion.div 
                                initial={{ opacity: 0, y: 20 }}
                                animate={{ opacity: 1, y: 0 }}
                                exit={{ opacity: 0, y: 20 }}
                                className="absolute bottom-32 left-1/2 -translate-x-1/2 z-[300] bg-white text-black px-6 py-3 rounded-full font-bold shadow-xl text-sm whitespace-nowrap"
                            >
                                {toastMessage}
                            </motion.div>
                        )}
                    </AnimatePresence>

                    {/* More Menu (Enhanced) */}
                    <AnimatePresence>
                        {isMoreMenuOpen && (
                            <motion.div 
                                initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
                                className="absolute inset-0 z-[250] bg-black/60 backdrop-blur-sm flex flex-col justify-end"
                                onClick={() => setIsMoreMenuOpen(false)}
                            >
                                <motion.div 
                                    initial={{ y: "100%" }} animate={{ y: 0 }} exit={{ y: "100%" }}
                                    transition={{ type: "tween", ease: "circOut", duration: 0.3 }}
                                    drag="y"
                                    dragConstraints={{ top: 0 }}
                                    dragElastic={{ top: 0, bottom: 0.2 }}
                                    onDragEnd={(_, info) => {
                                        if (info.offset.y > 100 || info.velocity.y > 100) {
                                            setIsMoreMenuOpen(false);
                                        }
                                    }}
                                    className="bg-[#242424] rounded-t-2xl flex flex-col max-h-[80vh] overflow-y-auto pb-6"
                                    onClick={e => e.stopPropagation()}
                                >
                                    {/* Drag Handle */}
                                    <div className="w-full flex justify-center pt-4 pb-2">
                                        <div className="w-10 h-1 bg-white/20 rounded-full"></div>
                                    </div>

                                    {/* Song Context Info */}
                                    <div className="flex items-center gap-3 px-6 pb-6 border-b border-white/5">
                                        <img src={getImageUrl(currentSong.image)} className="w-12 h-12 rounded-md object-cover shadow-lg" alt="" />
                                        <div>
                                            <div className="font-bold text-white text-[15px]">{currentSong.name}</div>
                                            <div className="text-sm text-white/60">{primaryArtistName}</div>
                                        </div>
                                    </div>

                                    {/* Menu Actions List */}
                                    <div className="flex flex-col py-2">

                                        <button onClick={() => { toggleLike(currentSong); setIsMoreMenuOpen(false); showToast(isLiked ? "Removed from Liked Songs" : "Added to Liked Songs"); }} className="flex items-center gap-4 px-6 py-3.5 hover:bg-white/5 active:bg-black/20 transition-colors">
                                            <Heart size={24} className={isLiked ? "text-[#1DB954] fill-[#1DB954]" : "text-white/80"} />
                                            <span className="text-white font-medium">{isLiked ? 'Liked' : 'Like'}</span>
                                        </button>

                                        {/* Download Option Added */}
                                        <button onClick={() => { setDownloadSong(currentSong); setIsMoreMenuOpen(false); }} className="flex items-center gap-4 px-6 py-3.5 hover:bg-white/5 active:bg-black/20 transition-colors">
                                            <Download size={24} className={isDownloaded ? "text-[#1DB954]" : "text-white/80"} />
                                            <span className="text-white font-medium">{isDownloaded ? 'Downloaded' : 'Download'}</span>
                                        </button>

                                        <button onClick={handleAddToQueue} className="flex items-center gap-4 px-6 py-3.5 hover:bg-white/5 active:bg-black/20 transition-colors">
                                            <ListPlus size={24} className="text-white/80" />
                                            <span className="text-white font-medium">Add to queue</span>
                                        </button>

                                        <button onClick={handleShare} className="flex items-center gap-4 px-6 py-3.5 hover:bg-white/5 active:bg-black/20 transition-colors">
                                            <Share2 size={24} className="text-white/80" />
                                            <span className="text-white font-medium">Share</span>
                                        </button>

                                        <button onClick={() => { setIsMoreMenuOpen(false); navigate(`/artist/${currentSong.artists.primary[0].id}`, { state: { artist: currentSong.artists.primary[0] } }); }} className="flex items-center gap-4 px-6 py-3.5 hover:bg-white/5 active:bg-black/20 transition-colors">
                                            <User size={24} className="text-white/80" />
                                            <span className="text-white font-medium">View Artist</span>
                                        </button>

                                        <button onClick={() => { setIsMoreMenuOpen(false); navigate(`/album/${currentSong.album.id}`); }} className="flex items-center gap-4 px-6 py-3.5 hover:bg-white/5 active:bg-black/20 transition-colors">
                                            <Disc size={24} className="text-white/80" />
                                            <span className="text-white font-medium">View Album</span>
                                        </button>

                                        <button onClick={handleSleepTimer} className="flex items-center gap-4 px-6 py-3.5 hover:bg-white/5 active:bg-black/20 transition-colors">
                                            <Moon size={24} className={sleepTimerId ? "text-[#1DB954]" : "text-white/80"} />
                                            <span className="text-white font-medium">{sleepTimerId ? 'Stop Sleep Timer' : 'Sleep Timer (30 mins)'}</span>
                                        </button>

                                        <button onClick={handleGoToRadio} className="flex items-center gap-4 px-6 py-3.5 hover:bg-white/5 active:bg-black/20 transition-colors">
                                            <Radio size={24} className="text-white/80" />
                                            <span className="text-white font-medium">Go to Song Radio</span>
                                        </button>

                                        <button onClick={() => showToast("Credits: Written by " + primaryArtistName)} className="flex items-center gap-4 px-6 py-3.5 hover:bg-white/5 active:bg-black/20 transition-colors">
                                            <Mic2 size={24} className="text-white/80" />
                                            <span className="text-white font-medium">Show credits</span>
                                        </button>

                                    </div>

                                </motion.div>
                            </motion.div>
                        )}
                    </AnimatePresence>
                </motion.div>
            ) : (
                <motion.div 
                    key="mini-player"
                    initial={{ y: 50, opacity: 0 }}
                    animate={{ y: 0, opacity: 1 }}
                    exit={{ y: 50, opacity: 0 }}
                    transition={{ type: "spring", stiffness: 400, damping: 30 }}
                    className="fixed bottom-[68px] md:bottom-4 left-2 right-2 md:left-1/2 md:-translate-x-1/2 md:w-[450px] h-[56px] z-[150] cursor-pointer isolate"
                    onClick={() => setFullScreen(true)}
                >
                    {/* Background */}
                    <div 
                        className="absolute inset-0 z-[-1] rounded-lg shadow-xl overflow-hidden"
                        style={{ backgroundColor: dominantColor }}
                    >
                         <div className="absolute inset-0 bg-black/20" />
                    </div>

                    <div className="flex items-center h-full px-2 gap-3">
                        {/* Image */}
                        <div className="h-10 w-10 shrink-0 rounded-[4px] overflow-hidden shadow-sm">
                            <img src={imageUrl} alt="" className="w-full h-full object-cover" />
                        </div>

                        {/* Text Info */}
                        <div className="flex-1 flex flex-col justify-center min-w-0 pr-2">
                            <span className="text-white font-bold text-xs truncate">
                                {currentSong.name}
                            </span>
                            <span className="text-white/70 text-[10px] truncate">
                                {primaryArtistName}
                            </span>
                        </div>

                        {/* Controls */}
                        <div className="flex items-center gap-1.5 pr-1 shrink-0">
                            {/* Like Button */}
                            <button onClick={(e) => { e.stopPropagation(); toggleLike(currentSong); }} className="shrink-0 p-1.5">
                                <Heart size={20} fill={isLiked ? "#1DB954" : "none"} className={isLiked ? "text-[#1DB954]" : "text-white"} />
                            </button>

                            {/* Previous Button (Hidden on very small screens if needed, but fitting here) */}
                            <button onClick={(e) => { e.stopPropagation(); prevSong(); }} className="shrink-0 p-1.5 text-white/90 hover:text-white">
                                <SkipBack size={22} fill="white" />
                            </button>

                            {/* Play/Pause Button */}
                            <button onClick={(e) => { e.stopPropagation(); togglePlay(); }} className="shrink-0 p-1.5">
                                {isBuffering ? (
                                    <Loader2 size={24} className="animate-spin text-white" />
                                ) : isPlaying ? (
                                    <Pause size={24} fill="white" className="text-white" />
                                ) : (
                                    <Play size={24} fill="white" className="text-white" />
                                )}
                            </button>

                            {/* Next Button */}
                            <button onClick={(e) => { e.stopPropagation(); nextSong(); }} className="shrink-0 p-1.5 text-white/90 hover:text-white">
                                <SkipForward size={22} fill="white" />
                            </button>
                        </div>
                    </div>

                    {/* Progress Bar (Mini only) */}
                    <div className="absolute bottom-0 left-1 right-1 h-[2px] bg-white/20 rounded-full overflow-hidden">
                        <div className="h-full bg-white rounded-full" style={{ width: `${(progress / (duration || 1)) * 100}%` }}></div>
                    </div>
                </motion.div>
            )}
        </AnimatePresence>

        {downloadSong && (
            <DownloadQualityModal song={downloadSong} onClose={() => setDownloadSong(null)} />
        )}
    </>
  );
};

import React, { useRef, useEffect, useState } from 'react';
import { Play, Pause, SkipBack, SkipForward, ChevronDown, MoreHorizontal, Download, ListMusic, Heart, Loader2, Shuffle, Repeat, PlusCircle, CheckCircle2, Disc, User, Share2, ListPlus, Radio, Mic2, Moon, Timer, X, Copy, Info } from 'lucide-react';
import { usePlayerStore } from '../store/playerStore';
import { api, getImageUrl, getAudioUrl, getOfflineAudioUrl } from '../services/api';
import { AnimatePresence, motion } from 'framer-motion';
import { DownloadQualityModal } from './DownloadQualityModal';
import { Song } from '../types';
import { useNavigate } from 'react-router-dom';

export const Player: React.FC = () => {
  const { 
    currentSong, 
    isPlaying, 
    isBuffering,
    isFullScreen,
    setFullScreen,
    togglePlay, 
    setIsPlaying, 
    setIsBuffering,
    nextSong, 
    prevSong,
    likedSongs,
    toggleLike,
    isShuffling,
    streamingQuality,
    isOfflineMode,
    downloadedSongIds,
    addToQueue
  } = usePlayerStore();

  const navigate = useNavigate();
  const audioRef = useRef<HTMLAudioElement>(null);

  const [progress, setProgress] = useState(0);
  const [duration, setDuration] = useState(0);
  const [dominantColor, setDominantColor] = useState<string>('#121212');
  const [isDragging, setIsDragging] = useState(false);

  const [downloadSong, setDownloadSong] = useState<Song | null>(null);
  const [isMoreMenuOpen, setIsMoreMenuOpen] = useState(false);

  // New States for enhanced features
  const [sleepTimerId, setSleepTimerId] = useState<number | null>(null);
  const [toastMessage, setToastMessage] = useState<string | null>(null);

  const [touchStart, setTouchStart] = useState<{x: number, y: number} | null>(null);

  const isLiked = currentSong ? likedSongs.some(s => s.id === currentSong.id) : false;
  const isDownloaded = currentSong ? downloadedSongIds.includes(currentSong.id) : false;

  // Extract color from image
  useEffect(() => {
    if (!currentSong) return;
    const imgUrl = getImageUrl(currentSong.image);
    const img = new Image();
    img.crossOrigin = "Anonymous";
    img.src = imgUrl;

    img.onload = () => {
      try {
        const canvas = document.createElement('canvas');
        const ctx = canvas.getContext('2d');
        if (!ctx) return;
        canvas.width = 1; 
        canvas.height = 1;
        ctx.drawImage(img, 0, 0, 1, 1);
        const [r, g, b] = ctx.getImageData(0, 0, 1, 1).data;
        setDominantColor(`rgb(${Math.max(20, r - 30)},${Math.max(20, g - 30)},${Math.max(20, b - 30)})`);
      } catch (e) {
        setDominantColor('#181818'); 
      }
    };
    img.onerror = () => setDominantColor('#181818');
  }, [currentSong?.id]);

  // MEDIA SESSION API INTEGRATION (Notification Poster)
  useEffect(() => {
    if (!currentSong || !('mediaSession' in navigator)) return;

    const artistName = currentSong.artists?.primary?.[0]?.name || "Unknown";
    // Get the high-quality image for the notification poster
    const hqImage = getImageUrl(currentSong.image);

    navigator.mediaSession.metadata = new MediaMetadata({
      title: currentSong.name,
      artist: artistName,
      album: currentSong.album?.name || "Single",
      artwork: [
          { src: hqImage, sizes: '96x96', type: 'image/jpeg' },
          { src: hqImage, sizes: '128x128', type: 'image/jpeg' },
          { src: hqImage, sizes: '192x192', type: 'image/jpeg' },
          { src: hqImage, sizes: '256x256', type: 'image/jpeg' },
          { src: hqImage, sizes: '384x384', type: 'image/jpeg' },
          { src: hqImage, sizes: '512x512', type: 'image/jpeg' },
      ]
    });

    navigator.mediaSession.setActionHandler('play', () => setIsPlaying(true));
    navigator.mediaSession.setActionHandler('pause', () => setIsPlaying(false));
    navigator.mediaSession.setActionHandler('previoustrack', prevSong);
    navigator.mediaSession.setActionHandler('nexttrack', nextSong);
    navigator.mediaSession.setActionHandler('seekto', (details) => {
        if (audioRef.current && details.seekTime !== undefined) {
            audioRef.current.currentTime = details.seekTime;
            setProgress(details.seekTime);
        }
    });
  }, [currentSong, setIsPlaying, prevSong, nextSong]);

  // Sync Playback State with Media Session
  useEffect(() => {
      if ('mediaSession' in navigator) {
          navigator.mediaSession.playbackState = isPlaying ? "playing" : "paused";
      }
  }, [isPlaying]);

  // Audio Source Logic
  useEffect(() => {
    if (!currentSong || !audioRef.current) return;

    const setAudioSource = async () => {
        let url = '';
        if (isOfflineMode || downloadedSongIds.includes(currentSong.id)) {
            const blobUrl = await getOfflineAudioUrl(currentSong.id);
            if (blobUrl) url = blobUrl;
            else if (isOfflineMode) { setIsPlaying(false); return; }
        }
        if (!url && !isOfflineMode) {
             url = getAudioUrl(currentSong.downloadUrl, streamingQuality);
        }
        if (url && audioRef.current && audioRef.current.src !== url) {
            const wasPlaying = isPlaying;
            audioRef.current.src = url;
            audioRef.current.load();
            if (wasPlaying) {
                 audioRef.current.play().catch(() => setIsPlaying(false));
            }
        }
    };
    setAudioSource();
  }, [currentSong?.id, streamingQuality, isOfflineMode]);

  useEffect(() => {
    const audio = audioRef.current;
    if (!audio) return;
    if (isPlaying && audio.paused) audio.play().catch(e => console.warn("Play interrupted", e));
    else if (!isPlaying && !audio.paused) audio.pause();
  }, [isPlaying]);

  const handleTimeUpdate = () => {
    if (audioRef.current && !isDragging) {
      const currentTime = audioRef.current.currentTime;
      const duration = audioRef.current.duration || 0;

      setProgress(currentTime);
      setDuration(duration);

      if ('mediaSession' in navigator && duration > 0 && !isNaN(duration)) {
          try {
            navigator.mediaSession.setPositionState({
                duration: duration,
                playbackRate: audioRef.current.playbackRate,
                position: currentTime
            });
          } catch (e) {}
      }
    }
  };

  const handleSeek = (e: React.ChangeEvent<HTMLInputElement>) => {
    const time = parseFloat(e.target.value);
    setProgress(time);
    if (audioRef.current) audioRef.current.currentTime = time;
  };

  const formatTime = (seconds: number) => {
    if (!seconds || isNaN(seconds)) return "-:--";
    const mins = Math.floor(seconds / 60);
    const secs = Math.floor(seconds % 60);
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  // Helper to show temporary messages
  const showToast = (msg: string) => {
      setToastMessage(msg);
      setTimeout(() => setToastMessage(null), 2500);
  };

  // --- ACTIONS FOR MORE MENU ---
  const handleAddToQueue = () => {
      if(currentSong) {
          addToQueue(currentSong);
          showToast("Added to queue");
          setIsMoreMenuOpen(false);
      }
  };

  const handleShare = async () => {
      if(!currentSong) return;
      const shareData = {
          title: currentSong.name,
          text: `Listen to ${currentSong.name} by ${currentSong.artists.primary[0].name}`,
          url: window.location.href
      };

      if (navigator.share) {
          try {
              await navigator.share(shareData);
          } catch(e) { console.log(e); }
      } else {
          navigator.clipboard.writeText(shareData.url);
          showToast("Link copied to clipboard");
      }
      setIsMoreMenuOpen(false);
  };

  const handleSleepTimer = () => {
      if (sleepTimerId) {
          clearTimeout(sleepTimerId);
          setSleepTimerId(null);
          showToast("Sleep timer turned off");
      } else {
          // Set for 30 mins
          const id = window.setTimeout(() => {
              setIsPlaying(false);
              setSleepTimerId(null);
          }, 30 * 60 * 1000); 
          setSleepTimerId(id);
          showToast("Sleep timer set for 30 minutes");
      }
      setIsMoreMenuOpen(false);
  };

  const handleGoToRadio = async () => {
      if(!currentSong) return;
      setIsMoreMenuOpen(false);
      showToast(`Starting radio for ${currentSong.name}`);

      try {
         // Fetch recommendations (mocked by searching artist)
         const query = currentSong.artists.primary[0]?.name || currentSong.name;
         const songs = await api.searchSongs(query);
         const newSongs = songs.filter(s => s.id !== currentSong.id);

         if (newSongs.length > 0) {
             // Add first 10 to queue
             newSongs.slice(0, 10).forEach(s => addToQueue(s));
             showToast(`Added ${Math.min(newSongs.length, 10)} songs to queue`);
         } else {
             showToast("No similar songs found");
         }
      } catch(e) {
          console.error("Radio failed", e);
          showToast("Failed to start radio");
      }
  };

  const handleTouchStart = (e: React.TouchEvent) => {
    setTouchStart({ x: e.targetTouches[0].clientX, y: e.targetTouches[0].clientY });
  };

  const handleTouchEnd = (e: React.TouchEvent) => {
    if (!touchStart) return;
    const touchEndX = e.changedTouches[0].clientX;
    const touchEndY = e.changedTouches[0].clientY;
    const diffX = touchStart.x - touchEndX;
    const diffY = touchStart.y - touchEndY;

    if (Math.abs(diffX) > 50 && Math.abs(diffX) > Math.abs(diffY)) {
      if (diffX > 0) nextSong();
      else prevSong();
    }
    if (diffY < -80 && Math.abs(diffY) > Math.abs(diffX) && !isMoreMenuOpen) {
        setFullScreen(false);
    }
    setTouchStart(null);
  };

  if (!currentSong) return null;

  const imageUrl = getImageUrl(currentSong.image);
  const primaryArtistName = currentSong.artists?.primary?.[0]?.name || "Unknown";

  return (
    <>
        <audio 
            ref={audioRef}
            preload="auto"
            onTimeUpdate={handleTimeUpdate}
            onEnded={nextSong}
            onWaiting={() => setIsBuffering(true)}
            onPlaying={() => setIsBuffering(false)}
            onCanPlay={() => setIsBuffering(false)}
            onPause={() => {
                if (isPlaying && !isBuffering && audioRef.current?.paused) setIsPlaying(false);
            }}
            onPlay={() => !isPlaying && setIsPlaying(true)}
        />

        <AnimatePresence mode="wait">
            {isFullScreen ? (
                <motion.div 
                    key="full-player"
                    initial={{ y: "100%" }}
                    animate={{ y: 0 }}
                    exit={{ y: "100%" }}
                    transition={{ type: "spring", damping: 30, stiffness: 300, mass: 0.8 }}
                    className="fixed inset-0 z-[200] flex flex-col bg-[#121212] isolate overflow-hidden"
                    onClick={(e) => e.stopPropagation()}
                    onTouchStart={handleTouchStart}
                    onTouchEnd={handleTouchEnd}
                >
                    {/* Background */}
                    <div 
                        className="absolute inset-0 z-[-1]"
                        style={{ 
                            background: `linear-gradient(to bottom, ${dominantColor}, #121212)`,
                        }}
                    />

                    {/* FULL PLAYER CONTENT */}
                    <div className="relative z-10 flex flex-col h-full px-6 pt-safe-top pb-safe-bottom">

                        {/* Header */}
                        <div className="flex items-center justify-between h-16 shrink-0 mt-2">
                            <button onClick={() => setFullScreen(false)} className="p-2 -ml-2 rounded-full hover:bg-white/10 shrink-0">
                                <ChevronDown size={28} className="text-white" />
                            </button>
                            <span className="text-[11px] font-bold tracking-[0.15em] uppercase text-white/70">
                                Now Playing
                            </span>
                            <button onClick={() => setIsMoreMenuOpen(true)} className="p-2 -mr-2 rounded-full hover:bg-white/10 shrink-0">
                                <MoreHorizontal size={24} className="text-white" />
                            </button>
                        </div>

                        {/* Main Artwork Area */}
                        <div className="flex-1 flex flex-col justify-center min-h-0 relative my-4">
                            <div className="relative w-full aspect-square max-w-[340px] mx-auto shadow-2xl rounded-xl overflow-hidden">
                                <img 
                                    src={imageUrl} 
                                    alt="Cover"
                                    className="w-full h-full object-cover"
                                />
                            </div>
                        </div>

                        {/* Info & Controls */}
                        <div className="flex flex-col gap-6 mb-10">
                            <div className="flex items-center justify-between">
                                <div className="flex flex-col overflow-hidden mr-4 min-w-0">
                                    <h2 className="text-2xl font-bold text-white truncate">
                                        {currentSong.name}
                                    </h2>
                                    <p className="text-lg text-white/70 truncate">
                                        {primaryArtistName}
                                    </p>
                                </div>
                                <button onClick={() => toggleLike(currentSong)} className="shrink-0">
                                    {isLiked ? <CheckCircle2 size={28} className="text-[#1DB954] fill-black" /> : <PlusCircle size={28} className="text-white/70" />}
                                </button>
                            </div>

                            {/* Scrubber */}
                            <div className="flex flex-col gap-2">
                                <div className="relative h-1 w-full bg-white/20 rounded-full group hover:h-1.5 transition-all">
                                     <div className="absolute left-0 top-0 bottom-0 bg-white rounded-full" style={{ width: `${(progress / (duration || 1)) * 100}%` }}>
                                        <div className="absolute right-0 top-1/2 -translate-y-1/2 w-3 h-3 bg-white rounded-full opacity-0 group-hover:opacity-100"></div>
                                     </div>
                                     <input 
                                        type="range" min="0" max={duration || 100} value={progress}
                                        onChange={handleSeek}
                                        onMouseDown={() => setIsDragging(true)}
                                        onTouchStart={() => setIsDragging(true)}
                                        onMouseUp={() => setIsDragging(false)}
                                        onTouchEnd={() => setIsDragging(false)}
                                        className="absolute inset-0 opacity-0 cursor-pointer"
                                    />
                                </div>
                                <div className="flex justify-between text-[11px] text-white/50 font-mono font-medium">
                                    <span>{formatTime(progress)}</span>
                                    <span>{formatTime(duration)}</span>
                                </div>
                            </div>

                            {/* Controls */}
                            <div className="flex items-center justify-between px-2">
                                <button className={`shrink-0 ${isShuffling ? 'text-[#1DB954]' : 'text-white/40'}`}><Shuffle size={20} /></button>
                                <button onClick={prevSong} className="shrink-0"><SkipBack size={32} className="text-white" fill="white" /></button>
                                <button 
                                    onClick={togglePlay}
                                    className="w-16 h-16 bg-white rounded-full flex items-center justify-center hover:scale-105 active:scale-95 transition-transform shrink-0"
                                >
                                    {isBuffering ? <Loader2 size={32} className="animate-spin text-black" /> : isPlaying ? <Pause size={32} fill="black" className="text-black" /> : <Play size={32} fill="black" className="ml-1 text-black" />}
                                </button>
                                <button onClick={nextSong} className="shrink-0"><SkipForward size={32} className="text-white" fill="white" /></button>
                                <button className="text-white/40 shrink-0"><Repeat size={20} /></button>
                            </div>

                            {/* Bottom Row */}
                            <div className="flex items-center justify-between px-4">
                                <button onClick={() => showToast("Lyrics coming soon")} className="text-white/50 shrink-0 hover:text-white transition-colors p-2">
                                    <Mic2 size={22} />
                                </button>
                                <button className="text-white/50 shrink-0 hover:text-white transition-colors p-2"><ListMusic size={22} /></button>
                            </div>
                        </div>
                    </div>

                    {/* Toast Notification */}
                    <AnimatePresence>
                        {toastMessage && (
                            <motion.div 
                                initial={{ opacity: 0, y: 20 }}
                                animate={{ opacity: 1, y: 0 }}
                                exit={{ opacity: 0, y: 20 }}
                                className="absolute bottom-32 left-1/2 -translate-x-1/2 z-[300] bg-white text-black px-6 py-3 rounded-full font-bold shadow-xl text-sm whitespace-nowrap"
                            >
                                {toastMessage}
                            </motion.div>
                        )}
                    </AnimatePresence>

                    {/* More Menu (Enhanced) */}
                    <AnimatePresence>
                        {isMoreMenuOpen && (
                            <motion.div 
                                initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
                                className="absolute inset-0 z-[250] bg-black/60 backdrop-blur-sm flex flex-col justify-end"
                                onClick={() => setIsMoreMenuOpen(false)}
                            >
                                <motion.div 
                                    initial={{ y: "100%" }} animate={{ y: 0 }} exit={{ y: "100%" }}
                                    transition={{ type: "tween", ease: "circOut", duration: 0.3 }}
                                    drag="y"
                                    dragConstraints={{ top: 0 }}
                                    dragElastic={{ top: 0, bottom: 0.2 }}
                                    onDragEnd={(_, info) => {
                                        if (info.offset.y > 100 || info.velocity.y > 100) {
                                            setIsMoreMenuOpen(false);
                                        }
                                    }}
                                    className="bg-[#242424] rounded-t-2xl flex flex-col max-h-[80vh] overflow-y-auto pb-6"
                                    onClick={e => e.stopPropagation()}
                                >
                                    {/* Drag Handle */}
                                    <div className="w-full flex justify-center pt-4 pb-2">
                                        <div className="w-10 h-1 bg-white/20 rounded-full"></div>
                                    </div>

                                    {/* Song Context Info */}
                                    <div className="flex items-center gap-3 px-6 pb-4">
                                        <img src={getImageUrl(currentSong.image)} className="w-12 h-12 rounded-md object-cover shadow-lg" alt="" />
                                        <div>
                                            <div className="font-bold text-white text-[15px]">{currentSong.name}</div>
                                            <div className="text-sm text-white/60">{primaryArtistName}</div>
                                        </div>
                                    </div>

                                    {/* New Download Card UI */}
                                    <div className="px-6 py-2">
                                        <button 
                                            onClick={() => { setDownloadSong(currentSong); setIsMoreMenuOpen(false); }} 
                                            className={`w-full flex items-center justify-between p-4 rounded-xl font-bold transition-all active:scale-95 border ${
                                                isDownloaded 
                                                ? 'bg-[#1DB954] border-[#1DB954] text-black' 
                                                : 'bg-[#333] border-white/5 text-white hover:bg-[#404040]'
                                            }`}
                                        >
                                            <div className="flex items-center gap-3">
                                                 <div className={`p-2 rounded-full ${isDownloaded ? 'bg-black/10' : 'bg-white/10'}`}>
                                                    <Download size={20} />
                                                 </div>
                                                 <div className="flex flex-col items-start">
                                                     <span className="text-sm">{isDownloaded ? 'Downloaded' : 'Download'}</span>
                                                     <span className={`text-[10px] font-medium ${isDownloaded ? 'text-black/70' : 'text-white/50'}`}>
                                                        {isDownloaded ? 'Available offline' : 'High Quality (320kbps)'}
                                                     </span>
                                                 </div>
                                            </div>
                                            {isDownloaded && <CheckCircle2 size={20} />}
                                        </button>
                                    </div>

                                    {/* Menu Actions List */}
                                    <div className="flex flex-col py-2">

                                        <button onClick={() => { toggleLike(currentSong); setIsMoreMenuOpen(false); showToast(isLiked ? "Removed from Liked Songs" : "Added to Liked Songs"); }} className="flex items-center gap-4 px-6 py-3.5 hover:bg-white/5 active:bg-black/20 transition-colors">
                                            <Heart size={24} className={isLiked ? "text-[#1DB954] fill-[#1DB954]" : "text-white/80"} />
                                            <span className="text-white font-medium">{isLiked ? 'Liked' : 'Like'}</span>
                                        </button>

                                        <button onClick={handleAddToQueue} className="flex items-center gap-4 px-6 py-3.5 hover:bg-white/5 active:bg-black/20 transition-colors">
                                            <ListPlus size={24} className="text-white/80" />
                                            <span className="text-white font-medium">Add to queue</span>
                                        </button>

                                        <button onClick={handleShare} className="flex items-center gap-4 px-6 py-3.5 hover:bg-white/5 active:bg-black/20 transition-colors">
                                            <Share2 size={24} className="text-white/80" />
                                            <span className="text-white font-medium">Share</span>
                                        </button>

                                        <button onClick={() => { setIsMoreMenuOpen(false); navigate(`/artist/${currentSong.artists.primary[0].id}`, { state: { artist: currentSong.artists.primary[0] } }); }} className="flex items-center gap-4 px-6 py-3.5 hover:bg-white/5 active:bg-black/20 transition-colors">
                                            <User size={24} className="text-white/80" />
                                            <span className="text-white font-medium">View Artist</span>
                                        </button>

                                        <button onClick={() => { setIsMoreMenuOpen(false); navigate(`/album/${currentSong.album.id}`); }} className="flex items-center gap-4 px-6 py-3.5 hover:bg-white/5 active:bg-black/20 transition-colors">
                                            <Disc size={24} className="text-white/80" />
                                            <span className="text-white font-medium">View Album</span>
                                        </button>

                                        <button onClick={handleSleepTimer} className="flex items-center gap-4 px-6 py-3.5 hover:bg-white/5 active:bg-black/20 transition-colors">
                                            <Moon size={24} className={sleepTimerId ? "text-[#1DB954]" : "text-white/80"} />
                                            <span className="text-white font-medium">{sleepTimerId ? 'Stop Sleep Timer' : 'Sleep Timer (30 mins)'}</span>
                                        </button>

                                        <button onClick={handleGoToRadio} className="flex items-center gap-4 px-6 py-3.5 hover:bg-white/5 active:bg-black/20 transition-colors">
                                            <Radio size={24} className="text-white/80" />
                                            <span className="text-white font-medium">Go to Song Radio</span>
                                        </button>

                                        <button onClick={() => showToast("Credits: Written by " + primaryArtistName)} className="flex items-center gap-4 px-6 py-3.5 hover:bg-white/5 active:bg-black/20 transition-colors">
                                            <Info size={24} className="text-white/80" />
                                            <span className="text-white font-medium">Show credits</span>
                                        </button>

                                    </div>

                                </motion.div>
                            </motion.div>
                        )}
                    </AnimatePresence>
                </motion.div>
            ) : (
                <motion.div 
                    key="mini-player"
                    initial={{ y: 50, opacity: 0 }}
                    animate={{ y: 0, opacity: 1 }}
                    exit={{ y: 50, opacity: 0 }}
                    transition={{ type: "spring", stiffness: 400, damping: 30 }}
                    className="fixed bottom-[68px] md:bottom-4 left-2 right-2 md:left-1/2 md:-translate-x-1/2 md:w-[450px] h-[56px] z-[150] cursor-pointer isolate"
                    onClick={() => setFullScreen(true)}
                >
                    {/* Background */}
                    <div 
                        className="absolute inset-0 z-[-1] rounded-lg shadow-xl overflow-hidden"
                        style={{ backgroundColor: dominantColor }}
                    >
                         <div className="absolute inset-0 bg-black/20" />
                    </div>

                    <div className="flex items-center h-full px-2 gap-3">
                        {/* Image */}
                        <div className="h-10 w-10 shrink-0 rounded-[4px] overflow-hidden shadow-sm">
                            <img src={imageUrl} alt="" className="w-full h-full object-cover" />
                        </div>

                        {/* Text Info */}
                        <div className="flex-1 flex flex-col justify-center min-w-0 pr-2">
                            <span className="text-white font-bold text-xs truncate">
                                {currentSong.name}
                            </span>
                            <span className="text-white/70 text-[10px] truncate">
                                {primaryArtistName}
                            </span>
                        </div>

                        {/* Controls */}
                        <div className="flex items-center gap-1.5 pr-1 shrink-0">
                            {/* Like Button */}
                            <button onClick={(e) => { e.stopPropagation(); toggleLike(currentSong); }} className="shrink-0 p-1.5">
                                <Heart size={20} fill={isLiked ? "#1DB954" : "none"} className={isLiked ? "text-[#1DB954]" : "text-white"} />
                            </button>

                            {/* Previous Button (Hidden on very small screens if needed, but fitting here) */}
                            <button onClick={(e) => { e.stopPropagation(); prevSong(); }} className="shrink-0 p-1.5 text-white/90 hover:text-white">
                                <SkipBack size={22} fill="white" />
                            </button>

                            {/* Play/Pause Button */}
                            <button onClick={(e) => { e.stopPropagation(); togglePlay(); }} className="shrink-0 p-1.5">
                                {isBuffering ? (
                                    <Loader2 size={24} className="animate-spin text-white" />
                                ) : isPlaying ? (
                                    <Pause size={24} fill="white" className="text-white" />
                                ) : (
                                    <Play size={24} fill="white" className="text-white" />
                                )}
                            </button>

                            {/* Next Button */}
                            <button onClick={(e) => { e.stopPropagation(); nextSong(); }} className="shrink-0 p-1.5 text-white/90 hover:text-white">
                                <SkipForward size={22} fill="white" />
                            </button>
                        </div>
                    </div>

                    {/* Progress Bar (Mini only) */}
                    <div className="absolute bottom-0 left-1 right-1 h-[2px] bg-white/20 rounded-full overflow-hidden">
                        <div className="h-full bg-white rounded-full" style={{ width: `${(progress / (duration || 1)) * 100}%` }}></div>
                    </div>
                </motion.div>
            )}
        </AnimatePresence>

        {downloadSong && (
            <DownloadQualityModal song={downloadSong} onClose={() => setDownloadSong(null)} />
        )}
    </>
  );
};

import React from 'react';
import { X, Download, Zap, Wifi, HardDrive, Music2, Check } from 'lucide-react';
import { Song } from '../types';
import { usePlayerStore } from '../store/playerStore';
import { motion } from 'framer-motion';

interface DownloadQualityModalProps {
  song: Song;
  onClose: () => void;
}

export const DownloadQualityModal: React.FC<DownloadQualityModalProps> = ({ song, onClose }) => {
  const { startDownload } = usePlayerStore();

  const handleDownload = (url: string, quality: string) => {
      const filename = `${song.name} (${quality}) - ${song.artists.primary[0]?.name || 'Artist'}.mp3`;
      startDownload(song, url, filename);
      onClose();
  };

  // Helper to map quality to metadata
  const getMetadata = (quality: string) => {
      const bitrate = parseInt(quality.replace(/\D/g, '')) || 0;
      if (bitrate >= 320) return { label: 'Lossless-like', icon: Zap, color: 'from-purple-500 to-indigo-500', size: '~8 MB' };
      if (bitrate >= 160) return { label: 'High Quality', icon: Music2, color: 'from-green-400 to-emerald-600', size: '~4 MB' };
      if (bitrate >= 96)  return { label: 'Standard', icon: Wifi, color: 'from-blue-400 to-blue-600', size: '~2.5 MB' };
      return { label: 'Data Saver', icon: HardDrive, color: 'from-orange-400 to-red-500', size: '< 1 MB' };
  };

  const sortedQualities = song.downloadUrl.slice().sort((a, b) => {
      const getBitrate = (q: string) => parseInt(q.replace(/\D/g, '')) || 0;
      return getBitrate(b.quality) - getBitrate(a.quality);
  });

  return (
    <div className="fixed inset-0 z-[300] flex items-center justify-center bg-black/90 backdrop-blur-md p-4 animate-in fade-in duration-200">
        <motion.div 
            initial={{ scale: 0.9, opacity: 0, y: 20 }}
            animate={{ scale: 1, opacity: 1, y: 0 }}
            exit={{ scale: 0.9, opacity: 0, y: 20 }}
            className="bg-[#121212] w-full max-w-2xl rounded-3xl overflow-hidden shadow-2xl border border-white/10 relative"
        >
            {/* Header */}
            <div className="p-8 pb-4 flex items-start justify-between">
                <div>
                    <h2 className="text-3xl font-black text-white mb-2 tracking-tight">Select Quality</h2>
                    <p className="text-white/60 text-lg line-clamp-1">{song.name} • {song.artists.primary[0]?.name}</p>
                </div>
                <button 
                    onClick={onClose} 
                    className="p-3 bg-white/5 hover:bg-white/10 rounded-full text-white transition-colors"
                >
                    <X size={24} />
                </button>
            </div>

            {/* Grid Options */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4 p-8 pt-4">
                {sortedQualities.map((option, idx) => {
